const docContentData = {
    "zh": {
        "sections": [
            {
                "id": "intro",
                "icon": "fa-rocket",
                "title": "快速创建",
                "description": "创建一个包含 plugin.json 的文件夹即可开始。",
                "content": "<section id=\"section-intro\" class=\"doc-section mb-5 animate-in\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">云语面板采用模块化架构，插件可以深度介入后端逻辑与前端 UI。每个插件都是一个独立的目录，包含元数据清单、后端入口和前端资源。打包时请将目录内容直接压缩为 ZIP 即可。</p>\n    \n\n    <div class=\"row g-4 mb-4\">\n    <div class=\"col-md-6\">\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">目录结构</span>\n    <span class=\"text-muted opacity-50\">Tree</span>\n    </div>\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>my-plugin/\n    ├── plugin.json       # 核心清单文件 (必须)\n    ├── index.js          # 后端逻辑入口 (可选)\n    ├── component/        # 前端组件目录 (可选)\n    │   └── Main.js       # 前端 Vue 组件\n    └── data/             # 插件私有数据 (自动创建)\n    └── ...           # 运行时生成的数据文件</code></pre>\n    \n    \n    </div>\n    </div>\n    <div class=\"col-md-6\">\n    <div class=\"code-block-wrapper h-100 shadow-sm rounded-4 overflow-hidden border\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">plugin.json</span>\n    <span class=\"text-muted opacity-50\">JSON</span>\n    </div>\n    <pre  class=\"p-3 small mb-0 dev-code-block h-100\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>{\n        \"id\": \"my-plugin\",\n        \"name\": {\n            \"zh\": \"我的插件\",\n            \"en\": \"My Plugin\"\n        },\n        \"version\": \"1.0.0\",\n        \"author\": \"Antigravity\",\n        \"description\": {\n            \"zh\": \"一个示例插件\",\n            \"en\": \"An example plugin\"\n        },\n        \"icon\": \"fa-rocket\",\n        \"color\": \"#4caf50\",\n        \"main\": \"index.js\",\n        \"defaultEnabled\": true,\n        \"permissions\": [\"file_system\"]\n    }</code></pre>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "manifest",
                "icon": "fa-file-code",
                "title": "plugin.json 清单参考",
                "description": "每个字段的类型、是否必须、默认值与合法取值",
                "content": "<section id=\"section-manifest\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">plugin.json 是插件的元数据清单文件，位于插件根目录下，是唯一必须存在的文件。系统通过此文件识别、加载和展示插件。</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small text-uppercase text-secondary tracking-wider\" style=\"font-size: 0.75rem;\">字段详细说明</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead>\n    <tr class=\"text-white opacity-75 border-bottom\">\n    <th>字段</th>\n    <th>类型</th>\n    <th>必须</th>\n    <th>默认值</th>\n    <th>说明</th>\n    </tr>\n    </thead>\n    <tbody>\n    <tr><td class=\"text-info font-monospace py-2\">id</td><td>string</td><td class=\"text-danger\">是</td><td>—</td><td>插件唯一标识符。只能包含小写字母、数字、连字符和下划线。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">name</td><td>string | object</td><td class=\"text-danger\">是</td><td>—</td><td>插件显示名称。支持两种格式：<br><strong>字符串</strong>：<code>&quot;My Plugin&quot;</code>（不区分语言）；<br><strong>对象</strong>：<code>{ &quot;zh&quot;: &quot;我的插件&quot;, &quot;en&quot;: &quot;My Plugin&quot; }</code>（多语言，推荐）。对象格式键名为语言代码，面板根据当前语言自动选择，回退顺序：当前语言 → en → zh → 第一个值。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">version</td><td>string</td><td class=\"text-danger\">是</td><td>—</td><td>版本号，如 1.0.0。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">description</td><td>string | object</td><td>否</td><td>—</td><td>功能描述。与 name 格式相同，支持字符串或多语言对象。示例：<code>{ &quot;zh&quot;: &quot;一个示例插件&quot;, &quot;en&quot;: &quot;An example plugin&quot; }</code></td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">author</td><td>string</td><td>否</td><td>—</td><td>作者信息。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">icon</td><td>string</td><td>否</td><td>\"fa-puzzle-piece\"</td><td>图标类名。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">color</td><td>string</td><td>否</td><td>\"primary\"</td><td>主题色。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">main</td><td>string</td><td>否</td><td>\"index.js\"</td><td>后端入口。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">defaultEnabled</td><td>boolean</td><td>否</td><td>true</td><td>默认启用。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">official</td><td>boolean</td><td>否</td><td>false</td><td>官方标记。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">permissions</td><td>string[]</td><td>否</td><td>[]</td><td>权限列表。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">homepage</td><td>string</td><td>否</td><td>\"\"</td><td>主页 URL。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">license</td><td>string</td><td>否</td><td>\"\"</td><td>许可证标识。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "dependencies",
                "icon": "fa-npm",
                "title": "NPM 依赖管理",
                "description": "",
                "content": "<section id=\"section-dependencies\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">插件系统深度集成了 NPM 依赖管理。您只需在 <code>plugin.json</code> 中声明 <code>dependencies</code>，面板会在安装或更新插件时自动处理安装逻辑。</p>\n    \n\n    <div class=\"row g-4\">\n    <div class=\"col-md-6\">\n    <div class=\"card border-0 shadow-sm rounded-4 h-100\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold text-warning mb-3\"><i class=\"fa-solid fa-cloud-arrow-down me-2\"></i>智能安装流程</h6>\n    <ul class=\"small text-muted mb-0 ps-3 lh-lg\">\n    <li>支持 <code>pnpm</code> 和 <code>npm</code> 自动回退</li>\n    <li>内置国内镜像源轮询，确保安装成功率</li>\n    <li>依赖物理隔离，各插件互不干扰</li>\n    </ul>\n    \n    </div>\n    </div>\n    </div>\n    <div class=\"col-md-6\">\n    <div class=\"card border-0 shadow-sm rounded-4 h-100\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold text-info mb-3\"><i class=\"fa-solid fa-shield-halved me-2\"></i>Module Isolation</h6>\n    <p class=\"text-muted mb-4 lh-lg\">面板为每个插件实现了 Scoped Require。每个插件的 <code>require()</code> 调用都以其自身目录为锚点进行寻址，无需担心版本冲突。</p>\n    \n    </div>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "backend",
                "icon": "fa-server",
                "title": "后端开发与 API 参考",
                "description": "",
                "content": "<section id=\"section-backend\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">插件后端脚本需导出一个异步函数，系统会自动注入 <code>api</code> 对象。该对象封装了所有可操作的接口。后端运行在 Node.js 环境中，除了可以使用面板核心提供的全局包（如 <code>express</code>, <code>fs-extra</code>）外，更推荐通过 <code>plugin.json</code> 的 <code>dependencies</code> 声明并使用插件私有的第三方包。每个插件都拥有独立的模块加载上下文，互不干扰。</p>\n    \n\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">入口函数签名</span>\n    <span class=\"text-muted opacity-50\">Javascript</span>\n    </div>\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>// index.js — 插件后端入口\n    module.exports = async function(api) {\n        // api 对象包含所有属性和方法\n\n        // 可选：返回一个包含 destroy 方法的对象\n        // 当插件被禁用或卸载时，destroy() 会被自动调用\n        return {\n            destroy: async () => {\n                // 清理资源：关闭进程、断开连接、清除定时器等\n            }\n        };\n    };</code></pre>\n    \n    \n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-circle-info me-2 text-info\"></i>api 对象只读属性</h5>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead>\n    <tr class=\"text-white opacity-75 border-bottom\">\n    <th>属性</th>\n    <th>类型</th>\n    <th>说明</th>\n    </tr>\n    </thead>\n    <tbody>\n    <tr><td class=\"text-info font-monospace py-2\">api.id</td><td>string</td><td>插件 ID，与 plugin.json 中的 id 一致。例如：'my-plugin'</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">api.manifest</td><td>object</td><td>完整的 plugin.json 清单对象。包含所有清单字段以及系统追加的内部字段：_dir (string) 插件绝对路径；_enabled (boolean) 是否启用；_installed (boolean) 是否已安装。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">api.io</td><td>SocketIO.Server</td><td>面板 Socket.IO 服务端实例。可用于全局广播。命名空间：/plugin/[插件ID]/[自定义路径]。</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">api.context</td><td>object</td><td>面板注入的上下文对象，包含运行时环境信息（详见下方 context 章节）。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-box-open me-2 text-info\"></i>api.context 上下文对象</h5>\n    <p class=\"text-muted mb-3 small\">通过 <code>api.context</code> 访问，也可以直接解构：<code>const { instancesDir, baseDir } = api.context;</code>。以下为所有可用字段：</p>\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead>\n    <tr class=\"text-white opacity-75 border-bottom\">\n    <th>字段</th>\n    <th>类型</th>\n    <th>说明</th>\n    </tr>\n    </thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">instancesDir</td><td>string</td><td>所有 MC 实例的根目录绝对路径。例如：'/opt/mc-panel/instances'。每个实例的目录名为实例 ID。</td></tr>\n    <tr><td class=\"font-monospace py-2\">baseDir</td><td>string</td><td>面板基础目录绝对路径。例如：'/opt/mc-panel'。属于系统根工作区。</td></tr>\n    <tr><td class=\"font-monospace py-2\">dataDir</td><td>string</td><td>面板全局数据目录绝对路径。例如：'/opt/mc-panel/data'。存放配置文件、Java 安装等。</td></tr>\n    <tr><td class=\"font-monospace py-2\">globalBackupDir</td><td>string</td><td>全局备份目录绝对路径。用于存放跨实例的全局备份 ZIP 文件。</td></tr>\n    <tr><td class=\"font-monospace py-2\">pluginsDir</td><td>string</td><td>插件安装目录绝对路径。例如：'/opt/mc-panel/plugins'。</td></tr>\n    <tr><td class=\"font-monospace py-2\">getConfig</td><td>function</td><td>获取面板配置的函数。用法：api.context.getConfig()。详见下方 api.getConfig() 说明。</td></tr>\n    <tr><td class=\"font-monospace py-2\">instancesState</td><td>Map&lt;string, object&gt;</td><td>所有实例的运行时状态 Map。键为实例 ID，包含：process, logHistory, onlinePlayers, detectedVersion 等。</td></tr>\n    <tr><td class=\"font-monospace py-2\">appendLog</td><td>function</td><td>向实例控制台追加日志的函数。签名：appendLog(instanceId: string, message: string)。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-code me-2 text-info\"></i>api 方法完整参考</h5>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.registerRoutes(prefix, setupFn)</h6>\n    <p class=\"small text-muted mb-2\">注册 HTTP API 路由。所有路由自动添加认证中间件，最终路径为 /api/plugins/[插件ID][prefix]。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>参数</th><th>类型</th><th>必须</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">prefix</td><td>string</td><td class=\"text-danger\">是</td><td>路由前缀。建议以 / 开头。如果 prefix 不以 / 开头，系统会自动补全。</td></tr>\n    <tr><td class=\"font-monospace\">setupFn</td><td>express.Router | function</td><td class=\"text-danger\">是</td><td>两种形式：<br>1. <strong>express.Router 实例</strong>（推荐）：直接传入配置好的 Router。<br>2. <strong>无参函数</strong>：传入返回 Router 对象的函数。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>// 方式一：直接传入 Router（推荐）\n    const router = express.Router();\n    router.get('/hello', (req, res) => res.json({ msg: 'Hello' }));\n    router.post('/data', (req, res) => res.json({ received: req.body }));\n    api.registerRoutes('/', router);\n    // 前端调用：GET /api/plugins/my-plugin/hello\n\n    // 方式二：传入函数\n    api.registerRoutes('/api', () => {\n        const router = express.Router();\n        router.get('/status', (req, res) => res.json({ ok: true }));\n        return router;\n    });\n    // 前端调用：GET /api/plugins/my-plugin/api/status\n\n    // 文件上传示例 (需要 multer)\n    const upload = multer({ dest: path.join(DATA_DIR, 'tmp_uploads') });\n    router.post('/upload', upload.single('file'), (req, res) => {\n        const file = req.file;\n        res.json({ success: true, filename: file.originalname });\n    });</code></pre>\n    \n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.registerPublicRoutes(prefix, setupFn)</h6>\n    <p class=\"small text-muted mb-2\">注册公开的 HTTP API 路由。这些路由不会经过身份验证，适合外部集成使用。最终路径为 /api/public/plugins/[插件ID][prefix]。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>参数</th><th>类型</th><th>必须</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">prefix</td><td>string</td><td class=\"text-danger\">是</td><td>路由前缀。最终路径 = /api/public/plugins/[插件ID] + prefix。</td></tr>\n    <tr><td class=\"font-monospace\">setupFn</td><td>express.Router | function</td><td class=\"text-danger\">是</td><td>同 registerRoutes。建议在此路由中自行实现 API Key 等安全验证。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>const router = express.Router();\n    router.get('/status', (req, res) => {\n        // 外部调用：GET /api/public/plugins/my-plugin/status\n        res.json({ online: true, version: '1.0.0' });\n    });\n    api.registerPublicRoutes('/', router);</code></pre>\n    \n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.registerSocket(namespace, handlers)</h6>\n    <p class=\"small text-muted mb-2\">注册 WebSocket 命名空间和事件处理器。返回 Socket.IO Namespace 实例。命名空间路径为 /plugin/[插件ID][namespace]。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>参数</th><th>类型</th><th>必须</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">namespace</td><td>string</td><td class=\"text-danger\">是</td><td>命名空间路径。建议以 / 开头。示例：'/live' → /plugin/my-plugin/live。</td></tr>\n    <tr><td class=\"font-monospace\">handlers</td><td>object</td><td class=\"text-danger\">是</td><td>事件处理器映射对象。键为事件名称，值为处理函数。函数签名：(socket, ...args) => void。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-2\"><strong>返回值</strong>：Socket.IO Namespace 实例。可用于向该命名空间的所有客户端广播：<code>ns.emit('event', data)</code>。</p>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>const ns = api.registerSocket('/live', {\n        'chat': (socket, message) => {\n            api.logger.info('收到聊天:', message);\n            ns.emit('chat_response', { echo: message });\n        },\n        'join_room': (socket, roomId) => {\n            socket.join(roomId);\n            socket.emit('joined', { roomId });\n        }\n    });\n\n    // 后端全局广播示例\n    ns.emit('notification', { msg: '系统维护通知' });</code></pre>\n    \n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.registerSidebarItem(item)</h6>\n    <p class=\"small text-muted mb-2\">注册前端侧边栏导航项。根据 location 的不同，可以显示在实例侧边栏或全局下拉菜单中。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>参数字段</th><th>类型</th><th>必须</th><th>默认值</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">item.id</td><td>string</td><td class=\"text-danger\">是</td><td>—</td><td>侧边栏项唯一标识符。建议格式：'[插件ID]-[功能名]'。</td></tr>\n    <tr><td class=\"font-monospace\">item.labelKey</td><td>string</td><td class=\"text-danger\">是</td><td>—</td><td>显示文本的 i18n 翻译键。系统通过 $t(item.labelKey) 翻译显示。示例：'plugins.my-plugin.title'</td></tr>\n    <tr><td class=\"font-monospace\">item.icon</td><td>string</td><td>是</td><td>—</td><td>FontAwesome 6 Free 实体图标类名（不带 fa-solid 前缀）。</td></tr>\n    <tr><td class=\"font-monospace\">item.color</td><td>string</td><td>否</td><td>—</td><td>图标颜色。支持 CSS 颜色关键字或 HEX 值。</td></tr>\n    <tr><td class=\"font-monospace\">item.view</td><td>string</td><td class=\"text-danger\">是</td><td>—</td><td>视图名称。点击时会设置 store.view。必须与 registerComponent 的 name 参数一致！</td></tr>\n    <tr><td class=\"font-monospace\">item.location</td><td>string</td><td>否</td><td><code>\"instance\"</code></td><td>侧边栏项显示位置。合法取值：'instance'（实例内可见）、'global'（全局下拉菜单）、'both'（两者皆显示）。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>// 实例级侧边栏项（默认，仅在管理特定实例时可见）\n    api.registerSidebarItem({\n        id: 'backup-manager',\n        labelKey: 'plugins.my-plugin.title',\n        icon: 'fa-box-archive',\n        color: '#f1c40f',\n        view: 'plugin-mc-panel-plugin-backup-main',\n        location: 'instance'\n    });\n\n    // 全局级菜单项（无需选择实例即可访问）\n    api.registerSidebarItem({\n        id: 'frp-manager',\n        labelKey: 'sidebar.frp_manager',\n        icon: 'fa-network-wired',\n        color: '#6366f1',\n        view: 'frp-manager',\n        location: 'global'\n    });</code></pre>\n    \n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.registerComponent(name, componentPath)</h6>\n    <p class=\"small text-muted mb-2\">注册前端 Vue 组件。系统会自动通过动态 import 加载组件文件并注册为全局组件。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>参数</th><th>类型</th><th>必须</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">name</td><td>string</td><td class=\"text-danger\">是</td><td>组件注册名称。必须与 registerSidebarItem 的 view 值一致，否则点击侧边栏无法渲染组件。</td></tr>\n    <tr><td class=\"font-monospace\">componentPath</td><td>string</td><td class=\"text-danger\">是</td><td>组件文件路径，相对于插件根目录。该文件必须是一个 ES Module，使用 export default 导出 Vue 3 选项对象。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-2\"><strong>组件加载机制</strong>：系统通过 <code>/api/plugins/[插件ID]/component/[组件名]</code> 端点提供组件文件服务，前端使用 <code>import()</code> 动态加载。组件必须使用 <code>export default</code> 导出。</p>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>api.registerComponent('plugin-my-plugin-main', 'component/Main.js');\n    // 组件文件 component/Main.js 必须使用 export default：\n    // export default { template: '...', setup() { ... } }</code></pre>\n    \n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.registerDashboardCard(name, componentName)</h6>\n    <p class=\"small text-muted mb-2\">注册仪表盘可视化卡片。卡片将显示在实例列表页面的顶部，适合展示全局系统状态或汇总数据。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>参数</th><th>类型</th><th>必须</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">name</td><td>string</td><td class=\"text-danger\">是</td><td>卡片唯一标识名。示例：'CPUStatus'、'MemoryUsage'</td></tr>\n    <tr><td class=\"font-monospace\">componentName</td><td>string</td><td class=\"text-danger\">是</td><td>关联的 Vue 组件名称。必须已经通过 registerComponent 注册。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>// 1. 首先注册组件\n    api.registerComponent('SystemStatusCard', 'component/SystemStatusCard.js');\n\n    // 2. 将组件挂载到仪表盘卡片插槽\n    api.registerDashboardCard('GlobalStatus', 'SystemStatusCard');</code></pre>\n    \n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getDataDir()</h6>\n    <p class=\"small text-muted mb-2\">获取插件私有数据目录绝对路径。如果目录不存在，会自动创建。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>项目</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td>参数</td><td>无</td></tr>\n    <tr><td>返回值</td><td>string — 插件私有数据目录绝对路径。格式：[插件目录]/data。</td></tr>\n    <tr><td>副作用</td><td>如果目录不存在，会自动调用 fs.ensureDirSync() 创建</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>const dataDir = api.getDataDir();\n    const configPath = path.join(dataDir, 'config.json');\n    await fs.writeJson(configPath, { setting: 'value' }, { spaces: 2 });</code></pre>\n    \n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getGlobalDataDir()</h6>\n    <p class=\"small text-muted mb-2\">获取面板全局数据目录路径。适合存放跨插件共享或需要持久化的数据。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>项目</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td>参数</td><td>无</td></tr>\n    <tr><td>返回值</td><td>string — 面板全局数据目录绝对路径。例如：'/opt/mc-panel/data'。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>const globalDir = api.getGlobalDataDir();\n    const myDataDir = path.join(globalDir, 'my-plugin');\n    await fs.ensureDir(myDataDir);</code></pre>\n    \n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getInstancesDir()</h6>\n    <p class=\"small text-muted mb-2\">获取 MC 实例根目录路径。等同于 api.context.instancesDir。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>项目</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td>参数</td><td>无</td></tr>\n    <tr><td>返回值</td><td>string — 实例根目录绝对路径。例如：'/opt/mc-panel/instances'。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getBaseDir()</h6>\n    <p class=\"small text-muted mb-2\">获取面板基础目录路径。等同于 api.context.baseDir。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>项目</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td>参数</td><td>无</td></tr>\n    <tr><td>返回值</td><td>string — 面板基础目录绝对路径。例如：'/opt/mc-panel'。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getActiveInstanceId()</h6>\n    <p class=\"small text-muted mb-2\">获取当前活跃的实例 ID。从 instances.json 中读取 activeInstanceId 字段，若未配置则返回 'default'。适用于插件需要知道当前用户正在管理哪个实例的场景。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>项目</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td>参数</td><td>无</td></tr>\n    <tr><td>返回值</td><td>string — 当前活跃实例 ID。例如：'my-server'、'default'。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getInstanceDir(instanceId?)</h6>\n    <p class=\"small text-muted mb-2\">获取指定实例的目录绝对路径。若不传 instanceId，则使用当前活跃实例。从 instances.json 中查找实例配置并拼接完整路径，确保多实例环境下路径正确。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>项目</th><th>类型</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td>instanceId</td><td>string?</td><td>可选。实例 ID，默认使用当前活跃实例。</td></tr>\n    <tr><td>返回值</td><td>string | null</td><td>实例目录绝对路径。例如：'/opt/mc-panel/instances/my-server'。若实例不存在则返回 null。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <h6 class=\"fw-bold mb-2 small text-muted\">使用示例</h6>\n    <pre class=\"bg-dark bg-opacity-10 rounded-3 p-3 small mb-0\"><code>// 在插件路由中使用\nconst withInstance = (req, res, next) => {\n    const instanceId = req.query.instanceId || api.getActiveInstanceId();\n    const instDir = api.getInstanceDir(instanceId);\n    if (!instDir) return res.status(404).json({ error: 'Instance not found' });\n    req.instDir = instDir;\n    next();\n};\n\n// 获取当前实例的数据库路径\nconst dbPath = path.join(api.getInstanceDir(), 'easyauth.db');</code></pre>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getConfig()</h6>\n    <p class=\"small text-muted mb-2\">获取面板完整配置对象。包含当前所有运行参数。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>项目</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td>参数</td><td>无</td></tr>\n    <tr><td>返回值</td><td>object — 面板配置对象（详见下方字段说明）</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <h6 class=\"fw-bold mb-2 small text-muted\">返回对象字段</h6>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>字段</th><th>类型</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">isSetup</td><td>boolean</td><td>面板是否已完成初始设置（2FA 配置）。</td></tr>\n    <tr><td class=\"font-monospace py-2\">sessionSecret</td><td>string</td><td>Session 加密密钥。</td></tr>\n    <tr><td class=\"font-monospace py-2\">sessionTimeout</td><td>number</td><td>会话超时时间（天数）。</td></tr>\n    <tr><td class=\"font-monospace py-2\">githubProxy</td><td>string</td><td>GitHub 代理地址。为空表示直连。</td></tr>\n    <tr><td class=\"font-monospace py-2\">modrinthApi</td><td>string</td><td>Modrinth API 基础地址。默认：'https://api.modrinth.com/v2'</td></tr>\n    <tr><td class=\"font-monospace py-2\">port</td><td>number</td><td>面板监听端口。默认：3000</td></tr>\n    <tr><td class=\"font-monospace py-2\">consoleInfoPosition</td><td>string</td><td>控制台信息面板位置。合法取值：'top'、'sidebar'、'hide'。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>const config = api.getConfig();\n    if (config.githubProxy) {\n        const proxiedUrl = originalUrl.replace('https://github.com', config.githubProxy);\n    }</code></pre>\n    \n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.logger</h6>\n    <p class=\"small text-muted mb-2\">插件专用日志记录器。所有输出自动添加 [Plugin:插件名] 前缀，便于在面板日志中区分来源。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>方法</th><th>签名</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">api.logger.info</td><td><code>(...args: any[]) => void</code></td><td>输出信息级别日志。</td></tr>\n    <tr><td class=\"font-monospace py-2\">api.logger.warn</td><td><code>(...args: any[]) => void</code></td><td>输出警告级别日志。</td></tr>\n    <tr><td class=\"font-monospace py-2\">api.logger.error</td><td><code>(...args: any[]) => void</code></td><td>输出错误级别日志。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>api.logger.info('插件初始化成功');\n    // 输出: [Plugin:MyPlugin] 插件初始化成功\n\n    api.logger.warn('未找到配置，使用默认值');\n    api.logger.error('连接失败:', error.message);</code></pre>\n    \n    \n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-file-code me-2 text-info\"></i>后端完整示例</h5>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">index.js — 完整后端示例</span>\n    <span class=\"text-muted opacity-50\">Javascript</span>\n    </div>\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>const fs = require('fs-extra');\n    const path = require('path');\n    const express = require('express');\n\n    module.exports = async function(api) {\n        const { registerRoutes, context } = api;\n        const { instancesDir, dataDir, getConfig } = context;\n        const DATA_DIR = api.getDataDir();\n        const CONFIG_FILE = path.join(DATA_DIR, 'config.json');\n\n        const readConfig = () => {\n            try { return fs.readJsonSync(CONFIG_FILE); }\n            catch (e) { return { items:[] }; }\n        };\n        const writeConfig = (config) => {\n            fs.writeJsonSync(CONFIG_FILE, config, { spaces: 2 });\n        };\n\n        const router = express.Router();\n\n        router.get('/items', (req, res) => {\n            const config = readConfig();\n            res.json(config.items);\n        });\n\n        router.post('/items', (req, res) => {\n            const { name, value } = req.body;\n            if (!name) return res.status(400).json({ error: 'name 必须存在' });\n            const config = readConfig();\n            config.items.push({ id: Date.now().toString(), name, value: value || '' });\n            writeConfig(config);\n            res.json({ success: true });\n        });\n\n        api.registerRoutes('/', router);\n\n        const ns = api.registerSocket('/live', {\n            'message': (socket, data) => ns.emit('broadcast', data)\n        });\n\n        api.registerSidebarItem({\n            id: 'my-plugin-main',\n            labelKey: 'plugins.my_plugin.title',\n            icon: 'fa-rocket',\n            color: '#6366f1',\n            view: 'my-plugin-view',\n            location: 'instance'\n        });\n\n        api.registerComponent('my-plugin-view', 'component/Main.js');\n\n        api.logger.info('插件已加载完成');\n\n        return {\n            destroy: async () => {\n                api.logger.info('插件正在卸载，正在清理资源...');\n            }\n        };\n    };</code></pre>\n    \n    \n    </div>\n    </section>"
            },
            {
                "id": "frontend",
                "icon": "fa-display",
                "title": "前端开发指南",
                "description": "使用 Vue 3 构建插件界面",
                "content": "<section id=\"section-frontend\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">插件前端使用 Vue 3 组件（ES Module 格式），通过 <code>api.registerComponent()</code> 注册后，系统会自动动态加载。组件文件必须使用 <code>export default</code> 导出组件选项对象。</p>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-puzzle-piece me-2 text-success\"></i> 可用导入模块 </h5>\n    <p class=\"text-muted mb-3 small\">以下是插件前端组件中可以使用的所有导入：</p>\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"text-white opacity-75 border-bottom\"><th>导入语句</th><th>来源</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">import { ref, reactive, computed, onMounted, onUnmounted, watch, getCurrentInstance } from '/js/vue.esm-browser.js'</td><td>Vue 3</td><td>Vue 3 Composition API。可用导出：<code>ref</code>、<code>reactive</code>、<code>computed</code>、<code>watch</code>、<code>watchEffect</code>、<code>onMounted</code>、<code>onUnmounted</code>、<code>onBeforeUnmount</code>、<code>nextTick</code>、<code>getCurrentInstance</code> 等 Vue 3 Composition API 全部导出。</td></tr>\n    <tr><td class=\"font-monospace py-2\">import { store } from '/js/store.js'</td><td>面板</td><td>全局响应式状态。Vue 3 reactive 对象，所有属性响应式。详见下方 store 参考表。</td></tr>\n    <tr><td class=\"font-monospace py-2\">import { api } from '/js/api.js'</td><td>面板</td><td>基于 axios 的认证 API 请求。自动附加 instanceId。详见下方 API 参考表。</td></tr>\n    <tr><td class=\"font-monospace py-2\">import { showToast, openModal, formatLog, waitForPanel, uploadFileWithChunk, isLargeFile } from '/js/utils.js'</td><td>面板</td><td>工具函数集合。详见下方工具函数参考表。</td></tr>\n    <tr><td class=\"font-monospace py-2\">import { socket } from '/js/socket.js'</td><td>面板</td><td>Socket.IO 客户端实例（默认命名空间）。用于监听面板全局事件。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-code me-2 text-success\"></i> 前端组件模板 </h5>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">component/Main.js — 前端组件完整模板</span>\n    <span class=\"text-muted opacity-50\">Javascript</span>\n    </div>\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>import { ref, onMounted, onUnmounted, getCurrentInstance } from '/js/vue.esm-browser.js';\n    import { api } from '/js/api.js';\n    import { store } from '/js/store.js';\n    import { showToast, openModal } from '/js/utils.js';\n\n    export default {\n        template: \\`\n        &lt;div class=\"animate-in\"&gt;\n        &lt;div class=\"page-header d-flex justify-content-between align-items-center mb-4\"&gt;\n        &lt;div class=\"d-flex align-items-center\"&gt;\n        &lt;button @click=\"store.view = store.prevView || 'instance-manager'\" class=\"btn-back me-3\"&gt;\n        &lt;i class=\"fa-solid fa-chevron-left\"&gt;&lt;/i&gt;\n        &lt;/button&gt;\n        &lt;div&gt;\n        &lt;h3 class=\"m-0 fw-bold d-flex align-items-center\"&gt;\n        &lt;i class=\"fa-solid fa-rocket me-3 text-primary\"&gt;&lt;/i&gt;\n        &lt;span&gt;plugins.my_plugin.title&lt;/span&gt;\n        &lt;/h3&gt;\n        &lt;/div&gt;\n        &lt;/div&gt;\n        &lt;button class=\"btn btn-primary rounded-pill px-4\" @click=\"loadData\"&gt;\n        &lt;i class=\"fa-solid fa-refresh me-1\"&gt;&lt;/i&gt;刷新\n        &lt;/button&gt;\n        &lt;/div&gt;\n        &lt;div v-if=\"loading\" class=\"text-center py-5\"&gt;\n        &lt;div class=\"spinner-border text-primary\"&gt;&lt;/div&gt;\n        &lt;/div&gt;\n        &lt;div v-else&gt;\n        &lt;!-- 这里放置你的页面内容 --&gt;\n        &lt;/div&gt;\n        &lt;/div&gt;\n        \\`,\n        setup() {\n            const { proxy } = getCurrentInstance();\n            const $t = proxy.$t;\n            const pluginApiBase = '/api/plugins/my-plugin';\n            const loading = ref(false);\n            const items = ref([]);\n\n            const loadData = async () => {\n                try {\n                    loading.value = true;\n                    const res = await api.get(\\`\\${pluginApiBase}/items\\`);\n                    items.value = res.data;\n                } catch (e) {\n                    showToast(e.response?.data?.error || e.message, 'danger');\n                } finally {\n                    loading.value = false;\n                }\n            };\n\n            onMounted(() => { loadData(); });\n            return { store, loading, items, loadData };\n        }\n    };</code></pre>\n    \n    \n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-database me-2 text-success\"></i> store 全局状态完整参考 </h5>\n    <p class=\"text-muted mb-3 small\">通过 <code>import { store } from '/js/store.js'</code> 导入。Vue 3 reactive 对象，所有属性响应式。可直接读取和修改。</p>\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead>\n    <tr class=\"text-white opacity-75 border-bottom\"><th>属性</th><th>类型</th><th>说明</th></tr>\n    </thead>\n    <tbody>\n    <tr><td class=\"text-success font-monospace py-2\">store.auth</td><td>object</td><td>认证状态对象，包含以下字段：<br><code>loggedIn</code> (boolean) 是否已登录；<code>isSetup</code> (boolean) 是否完成 2FA 设置；<code>qrCode</code> (string) 二维码 Data URL（仅设置阶段有值）；<code>secret</code> (string) 2FA 密钥（仅设置阶段有值）；<code>token</code> (string) 验证码。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.isSetup</td><td>boolean</td><td>面板是否已完成初始设置。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.lang</td><td>string</td><td>当前界面语言。合法取值：<code>'zh'</code>（中文，默认）、<code>'en'</code>（英文）。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.onlinePlayers</td><td>string[]</td><td>当前实例在线玩家名称列表。示例：<code>['Steve', 'Alex']</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.stats</td><td>object</td><td>系统与服务器状态对象，包含以下字段：<br><code>cpu</code> (string) CPU 使用率百分比，如 <code>'45.2'</code>；<code>mem</code> (object) 内存信息：<code>{ total: '15.9' (GB), used: '8.3' (GB), percentage: '52.3' (%) }</code>；<code>mc</code> (object) MC 服务器信息：<code>{ online: 5 (当前在线人数), maxPlayers: 20 (最大玩家数), port: '25565' (端口号), motd: 'A Minecraft Server' (MOTD) }</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.isRunning</td><td>boolean</td><td>当前实例 MC 服务器是否运行中。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.hasBackupMod</td><td>boolean</td><td>当前实例是否安装备份模组。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.hasEasyAuth</td><td>boolean</td><td>当前实例是否安装了 EasyAuth 模组。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.hasVoicechat</td><td>boolean</td><td>当前实例是否安装语音聊天模组。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.logs</td><td>string[]</td><td>当前实例控制台日志数组。最多 1000 行纯文本。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.view</td><td>string</td><td>当前视图名称。设置此值可切换页面。内置视图：<code>'instance-manager'</code>（实例列表）、<code>'dashboard'</code>（控制台）、<code>'properties'</code>（server.properties）、<code>'mods'</code>（模组管理）、<code>'modrinth'</code>（Modrinth 浏览）、<code>'files'</code>（文件管理）、<code>'backups'</code>（备份管理）、<code>'easyauth'</code>（EasyAuth）、<code>'voicechat'</code>（语音聊天）、<code>'players'</code>（玩家管理）、<code>'java'</code>（Java 管理）、<code>'about'</code>（关于）、<code>'plugins'</code>（插件管理）、<code>'panel-settings'</code>（面板设置）。插件视图为 registerSidebarItem 的 view 值。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.prevView</td><td>string</td><td>上一个视图名称。用于返回按钮。示例：<code>store.view = store.prevView</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.consoleInfoPosition</td><td>string</td><td>控制台信息面板位置。合法取值：'top'、'sidebar'、'hide'。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.currentInstanceId</td><td>string|null</td><td>当前管理的实例 ID。<code>null</code> 表示在实例列表页。示例：<code>'default'</code>、<code>'survival'</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.instanceList</td><td>object[]</td><td>所有实例列表。每个元素包含：<code>id</code> (string) 实例 ID；<code>name</code> (string) 实例显示名；<code>dir</code> (string) 实例目录绝对路径；<code>hasBackupMod</code> (boolean) 是否有备份模组；<code>backupStrategy</code> (string) 备份策略，合法值：<code>'panel'</code>、<code>'mod'</code>；<code>isRunning</code> (boolean) 是否运行中；<code>onlinePlayers</code> (number) 在线人数；<code>port</code> (string) 端口号。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.javaInstallations</td><td>object[]</td><td>已安装 Java 列表。每个元素包含：<code>id</code> (string) Java 安装 ID；<code>featureVersion</code> (number) 主版本号，如 <code>17</code>、<code>21</code>；<code>path</code> (string) 可执行文件绝对路径；<code>source</code> (string) 安装来源，合法值：<code>'local'</code>（手动添加）、<code>'panel'</code>（面板安装）。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.customLogoUrl</td><td>string</td><td>自定义 Logo URL。空字符串表示使用默认。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.customBgUrl</td><td>string</td><td>自定义背景图 URL。空字符串使用默认。格式：<code>'/api/appearance/background'</code> 或完整 URL。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.task</td><td>object</td><td>全局任务进度对象。用于全屏进度遮罩（ProgressModal 组件）。包含字段：<br><code>visible</code> (boolean) 是否显示进度遮罩；<br><code>title</code> (string) 任务标题，如 '系统更新'、'系统回档中'；<br><code>message</code> (string) 当前步骤描述；<br><code>subMessage</code> (string) 附加信息（如百分比文本）；<br><code>percent</code> (number) 进度百分比 0-100；<br><code>speed</code> (number) 传输速度（字节/秒），0 表示无速度信息；<br><code>canCancel</code> (boolean) 是否可取消；<br><code>onCancel</code> (function|null) 取消回调函数。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.dashboardCards</td><td>object[]</td><td>仪表盘卡片列表。由插件通过 api.registerDashboardCard 注册。每个元素包含：<code>name</code> (string) 卡片标识名；<code>componentName</code> (string) 关联的 Vue 组件名。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.pluginSidebarItems</td><td>object[]</td><td>所有插件注册的侧边栏项列表。每个元素包含：<code>id</code> (string) 侧边栏项 ID；<code>labelKey</code> (string) 翻译键；<code>icon</code> (string) FontAwesome 图标名；<code>color</code> (string) 图标颜色；<code>view</code> (string) 视图名称；<code>location</code> (string) 显示位置，合法值：<code>'instance'</code>、<code>'global'</code>、<code>'both'</code>；<code>pluginId</code> (string) 所属插件 ID；<code>component</code> (string) 关联组件名。</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.pluginComponents</td><td>object</td><td>所有插件注册的前端组件映射。键为组件名 (string)，值为组件信息对象：<code>{ pluginId: string, path: string }</code>。通常不需要直接操作此属性，系统会根据 <code>store.view</code> 自动加载对应组件。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-globe me-2 text-success\"></i> Frontend API Reference </h5>\n    <p class=\"text-muted mb-3 small\">通过 <code>import { api } from '/js/api.js'</code> 导入。基于 axios 封装，自动附加 <code>instanceId</code> 参数和认证信息。</p>\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"text-white opacity-75 border-bottom\"><th>方法</th><th>签名</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"text-success font-monospace py-2\">api.get</td><td><code>(url: string, config?: AxiosRequestConfig) =&gt; Promise&lt;AxiosResponse&gt;</code></td><td>发送 GET 请求。自动附加 instanceId 到 URL 参数。示例：<code>const res = await api.get('/api/plugins/my-plugin/items');</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">api.post</td><td><code>(url: string, data?: any, config?: AxiosRequestConfig) =&gt; Promise&lt;AxiosResponse&gt;</code></td><td>发送 POST 请求。<code>data</code> 为请求体（自动 JSON 序列化）；如果 <code>data</code> 是 <code>FormData</code> 则以 multipart 发送。自动附加 <code>instanceId</code> 到请求体。示例：<code>await api.post('/api/plugins/my-plugin/items', { name: 'test' });</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">api.put</td><td><code>(url: string, data?: any, config?: AxiosRequestConfig) =&gt; Promise&lt;AxiosResponse&gt;</code></td><td>发送 PUT 请求。参数同 <code>api.post</code>。示例：<code>await api.put('/api/plugins/my-plugin/config', { key: 'value' });</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">api.delete</td><td><code>(url: string, config?: AxiosRequestConfig) =&gt; Promise&lt;AxiosResponse&gt;</code></td><td>发送 DELETE 请求。自动附加 instanceId 查询参数。示例：<code>await api.delete('/api/plugins/my-plugin/items/123');</code></td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-0 mt-3\"><strong>请求拦截器行为</strong>：所有请求自动附加 <code>store.currentInstanceId</code> 作为参数。GET/DELETE 请求附加到 URL 查询参数；POST/PUT 请求附加到请求体（FormData 使用 <code>append</code>，JSON 对象使用展开运算符）。响应数据通过 <code>res.data</code> 获取。</p>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-wrench me-2 text-success\"></i> Utility Functions Reference </h5>\n    <p class=\"text-muted mb-3 small\">通过 <code>import { showToast, openModal, formatLog, waitForPanel, uploadFileWithChunk, isLargeFile } from '/js/utils.js'</code> 导入。</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-success font-monospace small\">showToast(msg, type, params)</h6>\n    <p class=\"small text-muted mb-2\">显示全局 Toast 提示消息。消息会在 3 秒后自动消失。如果 msg 是翻译键，会自动翻译。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>参数</th><th>类型</th><th>必须</th><th>默认值</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">msg</td><td>string</td><td class=\"text-danger\">是</td><td>—</td><td>提示消息文本或 i18n 翻译键。如果是翻译键（如 'common.saved'）会自动翻译；如果不是翻译键则直接显示原文。示例：'操作成功'、'common.error'</td></tr>\n    <tr><td class=\"font-monospace\">type</td><td>string</td><td>否</td><td><code>\"success\"</code></td><td>提示类型，决定颜色和图标。合法取值：'success'、'danger'、'warning'、'info'。</td></tr>\n    <tr><td class=\"font-monospace\">params</td><td>object</td><td>否</td><td><code>{}</code></td><td>翻译参数对象。用于替换模板中的占位符。示例：{ name: '备份' }。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>showToast('保存成功');                    // 成功提示（默认绿色）\n    showToast('操作失败', 'danger');           // 错误提示（红色）\n    showToast('请注意配置', 'warning');\n    showToast('正在处理中', 'info');            // 信息提示（蓝色）\n    showToast('common.saved', 'success');      // 使用翻译键\n    showToast('common.welcome', 'info', { name: 'Admin' }); // 携带翻译参数</code></pre>\n    \n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-success font-monospace small\">openModal(opts)</h6>\n    <p class=\"small text-muted mb-2\">打开全局模态对话框。支持确认、输入和选择三种模式。支持嵌套模态框（自动处理 z-index）。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>参数字段</th><th>类型</th><th>必须</th><th>默认值</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">opts.title</td><td>string</td><td>否</td><td><code>\"确认\"</code></td><td>模态框标题。示例：'删除确认'、'输入名称'</td></tr>\n    <tr><td class=\"font-monospace\">opts.message</td><td>string</td><td>否</td><td><code>\"\"</code></td><td>模态框正文消息。支持 HTML。</td></tr>\n    <tr><td class=\"font-monospace\">opts.mode</td><td>string</td><td>否</td><td><code>\"confirm\"</code></td><td>模态框模式。合法取值：'confirm'、'input'、'select'。</td></tr>\n    <tr><td class=\"font-monospace\">opts.inputValue</td><td>string</td><td>否</td><td><code>\"\"</code></td><td>输入框默认值。仅在 mode: 'input' 时有效。</td></tr>\n    <tr><td class=\"font-monospace\">opts.placeholder</td><td>string</td><td>否</td><td><code>\"\"</code></td><td>输入框占位符文本。仅在 mode: 'input' 时有效。</td></tr>\n    <tr><td class=\"font-monospace\">opts.options</td><td>Array&lt;string | {label: string, value: any}&gt;</td><td>否</td><td><code>[]</code></td><td>选项列表。仅在 mode: 'select' 时有效。支持两种格式：<br><strong>字符串数组</strong>：<code>['选项A', '选项B']</code>，选择后 callback 接收字符串；<br><strong>对象数组</strong>：<code>[{label: '显示文本', value: '实际值'}]</code>，选择后 callback 接收 value。</td></tr>\n    <tr><td class=\"font-monospace\">opts.suffix</td><td>string</td><td>否</td><td><code>\"\"</code></td><td>输入框后缀文本。仅在 mode: 'input' 时有效。显示在输入框右侧，常用于单位提示（如 '秒'、'MB'）。</td></tr>\n    <tr><td class=\"font-monospace\">opts.callback</td><td>function</td><td>否</td><td><code>null</code></td><td>确认回调函数。签名：<br>mode: 'confirm' → <code>() =&gt; void</code>；<br>mode: 'input' → <code>(inputValue: string) =&gt; void</code>；<br>mode: 'select' → <code>(selectedValue: string) =&gt; void</code>。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>// 确认模式\n    openModal({\n        title: \"删除确认\",\n        message: '确定要删除此项目吗？此操作不可撤销。',\n        mode: 'confirm',\n        callback: () => { showToast('已删除'); }\n    });\n\n    // 输入模式（带后缀和默认值）\n    openModal({\n        title: \"设置间隔\",\n        message: '请输入自动备份间隔：',\n        mode: 'input',\n        inputValue: \"30\",\n        placeholder: '输入数字',\n        suffix: '分钟',\n        callback: (val) => {\n            if (val) showToast('间隔已设为: ' + val + '分钟');\n        }\n    });\n\n    // 选择模式 — 字符串数组\n    openModal({\n        title: \"选择备份策略\",\n        message: '请选择备份方式：',\n        mode: 'select',\n        options: [\"面板备份\", \"模组备份\", \"手动备份\"],\n        callback: (choice) => { showToast(\"选择了: \" + choice); }\n    });\n\n    // 选择模式 — 对象数组（label 显示，value 回调）\n    openModal({\n        title: \"选择游戏模式\",\n        message: '请选择玩家游戏模式：',\n        mode: 'select',\n        inputValue: 'survival',\n        options: [\n            { label: '生存模式', value: 'survival' },\n            { label: '创造模式', value: 'creative' },\n            { label: '冒险模式', value: 'adventure' },\n            { label: '旁观模式', value: 'spectator' }\n        ],\n        callback: (val) => { sendCmd('gamemode ' + val + ' Steve'); }\n    });</code></pre>\n    \n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-success font-monospace small\">formatLog(log)</h6>\n    <p class=\"small text-muted mb-2\">格式化 MC 服务器日志文本，为 INFO/WARN/ERROR 标签添加 HTML 高亮标签。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>参数</th><th>类型</th><th>必须</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">log</td><td>string</td><td class=\"text-danger\">是</td><td>原始日志文本。示例：'[12:00:00 INFO]: Server started'</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-0\"><strong>返回值</strong>：string — 格式化后的 HTML 字符串。<code>[INFO]</code> → <code>&lt;span class=\"log-info\"&gt;INFO&lt;/span&gt;</code>；<code>[WARN]</code> → <code>&lt;span class=\"log-warn\"&gt;WARN&lt;/span&gt;</code>；<code>[ERROR]</code> → <code>&lt;span class=\"log-error\"&gt;ERROR&lt;/span&gt;</code>；<code>[系统]</code> → <code>&lt;span class=\"log-system\"&gt;[系统]&lt;/span&gt;</code>。同时转义 < 为 &lt;。</p>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-success font-monospace small\">waitForPanel(targetPort)</h6>\n    <p class=\"small text-muted mb-2\">等待面板重新上线。用于重启面板后，轮询直到面板恢复响应。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>参数</th><th>类型</th><th>必须</th><th>默认值</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">targetPort</td><td>string|number|null</td><td>否</td><td><code>null</code></td><td>目标端口号。如果提供，则探测相应端口；如果为 null，则探测当前页面的版本接口。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-0\"><strong>返回值</strong>: Promise&lt;void&gt; — 面板恢复响应时 resolve。初始等待 1.5 秒后开始探测，每次探测间隔 1 秒，单次探测超时 2 秒。</p>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-success font-monospace small\">uploadFileWithChunk(file, options)</h6>\n    <p class=\"small text-muted mb-2\">大文件分片上传。仅当文件 ≥ 100MB 时启用分片上传，小于 100MB 的文件返回 null，需使用普通上传方式。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>参数字段</th><th>类型</th><th>必须</th><th>默认值</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">file</td><td>File</td><td class=\"text-danger\">是</td><td>—</td><td>要上传的文件对象（浏览器 File API）。</td></tr>\n    <tr><td class=\"font-monospace\">options.initUrl</td><td>string</td><td class=\"text-danger\">是</td><td>—</td><td>初始化上传的 API 端点。POST 请求，后端应返回 { uploadId: string }。</td></tr>\n    <tr><td class=\"font-monospace\">options.uploadUrl</td><td>string</td><td>否</td><td><code>\"/api/files/chunk/upload\"</code></td><td>分片上传 API 端点。POST 请求，发送 FormData。</td></tr>\n    <tr><td class=\"font-monospace\">options.completeUrl</td><td>string</td><td class=\"text-danger\">是</td><td>—</td><td>完成上传的 API 端点。POST 请求，发送 { uploadId }。</td></tr>\n    <tr><td class=\"font-monospace\">options.cancelUrl</td><td>string</td><td>否</td><td><code>\"/api/files/chunk/cancel\"</code></td><td>取消上传的 API 端点。上传失败时自动调用。</td></tr>\n    <tr><td class=\"font-monospace\">options.fieldName</td><td>string</td><td>否</td><td><code>\"chunk\"</code></td><td>FormData 中分片文件的字段名。</td></tr>\n    <tr><td class=\"font-monospace\">options.extraInitData</td><td>object</td><td>否</td><td><code>{}</code></td><td>初始化请求的额外数据。会合并到 initUrl 的请求体中。</td></tr>\n    <tr><td class=\"font-monospace\">options.onProgress</td><td>function</td><td>否</td><td><code>() =&gt; {}</code></td><td>进度回调函数。签名：<code>(uploadedBytes: number, totalBytes: number, chunkIndex: number, totalChunks: number) =&gt; void</code>。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-0\"><strong>返回值</strong>：Promise<object|null> — 文件 < 100MB 返回 null；≥ 100MB 返回完成请求的响应数据。分片大小为 10MB。上传失败时自动调用取消接口。</p>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-success font-monospace small\">isLargeFile(file)</h6>\n    <p class=\"small text-muted mb-2\">检查文件是否为大文件 (≥ 100MB)。用于决定是否使用分片上传。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>参数</th><th>类型</th><th>必须</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">file</td><td>File</td><td class=\"text-danger\">是</td><td>浏览器 File 对象。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-0\"><strong>返回值</strong>：boolean — true 表示文件 ≥ 100MB，应使用 uploadFileWithChunk；false 表示文件较小，使用普通上传。</p>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "vue-options",
                "icon": "fa-cubes",
                "title": "Vue 组件选项与内置组件",
                "description": "组件声明规范、子组件注册、内置可复用组件",
                "content": "<section id=\"section-vue-options\" class=\"doc-section mb-5\">\n    \n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-file-code me-2\" style=\"color: #8b5cf6;\"></i>组件选项对象完整字段</h5>\n    <p class=\"text-muted mb-3 small\">前端组件文件必须使用 <code>export default {}</code> 导出选项对象。以下是所有可用字段：</p>\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"text-white opacity-75 border-bottom\"><th>字段</th><th>类型</th><th>必须</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">template</td><td>string</td><td class=\"text-danger\">是</td><td>组件 HTML 模板字符串。使用 ES6 模板字面量（反引号）。支持 Vue 3 模板语法：v-if、v-for、v-model、@click、:class 等。</td></tr>\n    <tr><td class=\"font-monospace py-2\">setup()</td><td>function</td><td class=\"text-danger\">是</td><td>Composition API 入口函数。返回的对象属性在模板中可用。签名：<code>() =&gt; Object</code>。必须返回模板中使用的所有响应式变量和方法。</td></tr>\n    <tr><td class=\"font-monospace py-2\">components</td><td>object</td><td>否</td><td>注册子组件。键为组件标签名（PascalCase），值为导入的组件对象。注册后可在 template 中使用 kebab-case 标签引用。示例：<code>components: { Avatar, CustomSelect }</code> → <code>&lt;avatar&gt;&lt;/avatar&gt;</code></td></tr>\n    <tr><td class=\"font-monospace py-2\">props</td><td>object</td><td>否</td><td>组件属性定义。支持简写和完整格式。简写：<code>props: { name: String }</code>；完整：<code>props: { name: { type: String, required: true, default: '' } }</code>。父组件通过属性传递：<code>&lt;my-comp name='test'&gt;</code></td></tr>\n    <tr><td class=\"font-monospace py-2\">emits</td><td>string[]</td><td>否</td><td>声明组件可触发的事件。示例：<code>emits: ['update', 'delete']</code>。在 setup 中通过第二个参数 <code>{ emit }</code> 触发：<code>emit('update', newValue)</code>。</td></tr>\n    <tr><td class=\"font-monospace py-2\">name</td><td>string</td><td>否</td><td>组件名称。用于递归组件和 DevTools 调试。示例：<code>name: 'MyPluginView'</code></td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-puzzle-piece me-2\" style=\"color: #8b5cf6;\"></i>在 setup() 中获取 $t 翻译函数</h5>\n    <p class=\"text-muted mb-3 small\">在模板中可以直接使用 <code>$t('key')</code>，但在 <code>setup()</code> 函数内需要通过 <code>getCurrentInstance()</code> 获取：</p>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>import { getCurrentInstance } from '/js/vue.esm-browser.js';\n\nexport default {\n    setup() {\n        const { proxy } = getCurrentInstance();\n        const $t = proxy.$t;\n\n        // 在 JS 逻辑中使用翻译\n        const title = $t('plugins.my-plugin.title');\n        showToast($t('common.success'));\n\n        // ...\n    }\n};</code></pre>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-boxes-stacked me-2\" style=\"color: #8b5cf6;\"></i>内置可复用组件</h5>\n    <p class=\"text-muted mb-3 small\">面板提供了以下内置组件，插件可以直接导入使用。在组件选项中通过 <code>components</code> 字段注册后即可在模板中使用。</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 small\" style=\"color: #8b5cf6;\"><i class=\"fa-solid fa-user me-2\"></i>Avatar — 玩家头像</h6>\n    <p class=\"small text-muted mb-2\">自动检测玩家皮肤来源（正版/LittleSkin），显示玩家头像。支持 CSS 像素风裁剪。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>导入</th><th>说明</th></tr></thead>\n    <tbody><tr><td class=\"font-monospace\">import Avatar from '/js/components/Avatar.js'</td><td>玩家头像组件</td></tr></tbody>\n    </table>\n    </div>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Props</th><th>类型</th><th>必须</th><th>默认值</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">player</td><td>string</td><td class=\"text-danger\">是</td><td>—</td><td>玩家名称。</td></tr>\n    <tr><td class=\"font-monospace\">size</td><td>number</td><td>否</td><td>64</td><td>头像尺寸（像素）。常用值：24（列表小头像）、64（卡片大头像）。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>import Avatar from '/js/components/Avatar.js';\n\nexport default {\n    components: { Avatar },\n    template: \\`\n        &lt;div&gt;\n            &lt;!-- 大头像 --&gt;\n            &lt;avatar :player=\"playerName\" :size=\"64\"&gt;&lt;/avatar&gt;\n            &lt;!-- 列表小头像 --&gt;\n            &lt;avatar :player=\"p\" :size=\"24\" class=\"me-2\"&gt;&lt;/avatar&gt;\n        &lt;/div&gt;\n    \\`,\n    setup() {\n        const playerName = ref('Steve');\n        return { playerName };\n    }\n};</code></pre>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 small\" style=\"color: #8b5cf6;\"><i class=\"fa-solid fa-list me-2\"></i>CustomSelect — 自定义下拉选择器</h6>\n    <p class=\"small text-muted mb-2\">功能丰富的自定义下拉选择组件，支持搜索、键盘导航、自动定位。使用 Teleport 渲染到 body 层，避免溢出问题。</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>导入</th><th>说明</th></tr></thead>\n    <tbody><tr><td class=\"font-monospace\">import CustomSelect from '/js/components/CustomSelect.js'</td><td>自定义下拉选择组件</td></tr></tbody>\n    </table>\n    </div>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Props</th><th>类型</th><th>必须</th><th>默认值</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">modelValue</td><td>any</td><td>否</td><td>''</td><td>当前选中值。支持 v-model 双向绑定。</td></tr>\n    <tr><td class=\"font-monospace\">options</td><td>Array&lt;string | {label: string, value: any}&gt;</td><td>否</td><td>[]</td><td>选项列表。支持字符串数组和对象数组（同 openModal）。</td></tr>\n    <tr><td class=\"font-monospace\">placeholder</td><td>string</td><td>否</td><td>''</td><td>占位提示文本。</td></tr>\n    <tr><td class=\"font-monospace\">disabled</td><td>boolean</td><td>否</td><td>false</td><td>是否禁用。</td></tr>\n    <tr><td class=\"font-monospace\">size</td><td>string</td><td>否</td><td>''</td><td>尺寸。合法取值：<code>''</code>（默认）、<code>'sm'</code>（小）、<code>'lg'</code>（大）。</td></tr>\n    <tr><td class=\"font-monospace\">searchable</td><td>boolean</td><td>否</td><td>false</td><td>是否启用搜索过滤功能。</td></tr>\n    <tr><td class=\"font-monospace\">width</td><td>string</td><td>否</td><td>''</td><td>自定义宽度。CSS 值，如 '200px'、'100%'。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Events</th><th>参数</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">update:modelValue</td><td>value: any</td><td>选中值变化时触发。用于 v-model。</td></tr>\n    <tr><td class=\"font-monospace\">change</td><td>value: any</td><td>选中值变化时触发。用于监听变化执行逻辑。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>import CustomSelect from '/js/components/CustomSelect.js';\n\nexport default {\n    components: { CustomSelect },\n    template: \\`\n        &lt;div&gt;\n            &lt;!-- 基础用法 --&gt;\n            &lt;custom-select\n                v-model=\"selectedMode\"\n                :options=\"modeOptions\"\n                placeholder=\"选择模式\"\n            /&gt;\n\n            &lt;!-- 带搜索 --&gt;\n            &lt;custom-select\n                v-model=\"selectedPlayer\"\n                :options=\"store.onlinePlayers\"\n                searchable\n                placeholder=\"搜索玩家\"\n                size=\"sm\"\n            /&gt;\n        &lt;/div&gt;\n    \\`,\n    setup() {\n        const selectedMode = ref('');\n        const modeOptions = [\n            { label: '生存模式', value: 'survival' },\n            { label: '创造模式', value: 'creative' }\n        ];\n        const selectedPlayer = ref('');\n        return { selectedMode, modeOptions, selectedPlayer, store };\n    }\n};</code></pre>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 small\" style=\"color: #8b5cf6;\"><i class=\"fa-solid fa-spinner me-2\"></i>ProgressModal — 全局进度遮罩</h6>\n    <p class=\"small text-muted mb-2\">全屏毛玻璃进度遮罩组件，已在全局注册，插件无需导入。通过 <code>store.task</code> 控制显示和内容。</p>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>// 显示进度遮罩\nstore.task.visible = true;\nstore.task.title = '导出数据';\nstore.task.message = '正在处理...';\nstore.task.percent = 50;\nstore.task.speed = 0;\nstore.task.canCancel = true;\nstore.task.onCancel = () => {\n    store.task.visible = false;\n    showToast('已取消', 'warning');\n};\n\n// 更新进度\nstore.task.percent = 80;\nstore.task.message = '即将完成...';\n\n// 完成后关闭\nstore.task.percent = 100;\nstore.task.message = '完成！';\nsetTimeout(() => { store.task.visible = false; }, 1000);</code></pre>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "i18n",
                "icon": "fa-globe",
                "title": "国际化 (i18n)",
                "description": "",
                "content": "<section id=\"section-i18n\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">面板支持插件独立的国际化配置。插件可以在其根目录下创建 <code>locales/</code> 目录，放置 JSON 格式的翻译文件。系统会自动加载并在前端合并这些翻译。</p>\n    \n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-folder-tree me-2 text-info\"></i>目录结构</h5>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>my-plugin/\n    ├── locales/\n    │   ├── zh.json    # 中文翻译\n    │   └── en.json    # 英文翻译\n    ├── component/\n    │   └── Main.js\n    └── plugin.json</code></pre>\n    \n    \n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-file-code me-2 text-info\"></i>Translation Example (zh.json)</h5>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>{\n        \"title\": \"我的插件\",\n        \"description\": \"这是一个测试插件\",\n        \"buttons\": {\n            \"start\": \"开始任务\",\n            \"stop\": \"停止任务\"\n        }\n    }</code></pre>\n    \n    \n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-tag me-2 text-info\"></i>命名空间规则</h5>\n    <p class=\"text-muted mb-4 lh-lg\">为了避免不同插件之间的词条冲突，系统会将插件的所有翻译自动挂载到 <code>plugins.[pluginId]</code> 命名空间下。</p>\n    \n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <ul class=\"small text-muted mb-0 ps-3 lh-lg\">\n    <li><i class=\"fa-solid fa-check text-success me-2\"></i>如果插件 ID 为 <code>my-plugin</code>，并且翻译文件中有 <code>\"title\": \"你好\"</code></li>\n    <li><i class=\"fa-solid fa-check text-success me-2\"></i>前端调用键名为：<code>plugins.my-plugin.title</code></li>\n    <li><i class=\"fa-solid fa-check text-success me-2\"></i>侧边栏注册时的 <code>labelKey</code> 应该是：<code>plugins.my-plugin.title</code></li>\n    </ul>\n    \n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-terminal me-2 text-info\"></i>前端组件中使用</h5>\n    <p class=\"text-muted mb-4 lh-lg\">在 Vue 模板中直接使用全局 <code>$t()</code> 函数即可：</p>\n    \n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>&lt;template&gt;\n    &lt;div&gt;\n    &lt;h3&gt;plugins.my-plugin.title&lt;/h3&gt;\n    &lt;button&gt;plugins.my-plugin.buttons.start&lt;/button&gt;\n    &lt;/div&gt;\n    &lt;/template&gt;</code></pre>\n    </div>\n    </section>"
            },
            {
                "id": "socket",
                "icon": "fa-plug",
                "title": "Socket.IO 实战",
                "description": "实时双向数据交互",
                "content": "<section id=\"section-socket\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">面板内置了 Socket.IO，插件可以注册独立的命名空间，实现与前端的实时通信（如控制台日志流、实时状态监控等）。</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small text-uppercase text-warning tracking-wider\" style=\"font-size: 0.75rem;\">Panel Global Events (Default Namespace)</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead>\n    <tr class=\"text-white opacity-75 border-bottom\"><th>事件名</th><th>数据结构</th><th>说明</th></tr>\n    </thead>\n    <tbody>\n    <tr><td class=\"text-warning font-monospace py-2\">status</td><td>{ isRunning: boolean }</td><td>当前活跃实例的运行状态变更。</td></tr>\n    <tr><td class=\"text-warning font-monospace py-2\">status:{instanceId}</td><td>{ isRunning: boolean }</td><td>特定实例的运行状态变更。</td></tr>\n    <tr><td class=\"text-warning font-monospace py-2\">players_update</td><td>string[]</td><td>当前活跃实例的在线玩家列表更新。</td></tr>\n    <tr><td class=\"text-warning font-monospace py-2\">players_update:{instanceId}</td><td>string[]</td><td>指定实例的在线玩家列表更新。</td></tr>\n    <tr><td class=\"text-warning font-monospace py-2\">system_stats</td><td>object</td><td>系统状态更新。包含：cpu (string) CPU 使用率；mem (object) 内存信息；mc (object) MC 服务器信息。</td></tr>\n    <tr><td class=\"text-warning font-monospace py-2\">instances_update</td><td>object[]</td><td>实例列表更新。数据格式同 store.instanceList。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-code me-2 text-warning\"></i>插件自定义 Socket 命名空间</h5>\n    <p class=\"text-muted mb-3 small\">插件后端通过 api.registerSocket(namespace, handlers) 创建独立的 Socket 命名空间。前端连接方法如下：</p>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">插件 Socket 前后端通信示例</span>\n    <span class=\"text-muted opacity-50\">Javascript</span>\n    </div>\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>// === 后端 index.js ===\n    const ns = api.registerSocket('/live', {\n        'chat': (socket, message) => {\n            api.logger.info('收到消息:', message);\n            ns.emit('chat_response', { echo: message, from: socket.id });\n        },\n        'request_data': (socket, params) => {\n            socket.emit('data_response', { result: 'processed', params });\n        }\n    });\n\n    // 向所有客户端广播\n    // ns.emit('notification', { msg: '系统维护通知' });\n\n    // === 前端 component/Main.js ===\n    import { ref, onMounted, onUnmounted } from '/js/vue.esm-browser.js';\n\n    export default {\n        template: '&lt;div&gt;{{ message }}&lt;/div&gt;',\n        setup() {\n            const message = ref('');\n            let pluginSocket = null;\n\n            onMounted(async () => {\n                // 动态导入 Socket.IO 客户端\n                const { io: ioClient } = await import('/socket.io/socket.io.esm.min.js');\n\n                // 方式一：连接到插件的自定义命名空间\n                pluginSocket = ioClient('/plugin/my-plugin/live');\n                pluginSocket.on('chat_response', (data) => {\n                    message.value = data.echo;\n                });\n                pluginSocket.on('notification', (data) => {\n                    message.value = data.msg;\n                });\n\n                // 方式二：使用默认命名空间（监听面板全局事件）\n                // pluginSocket = ioClient();\n                // pluginSocket.on('system_stats', (data) => { ... });\n            });\n\n            onUnmounted(() => {\n                if (pluginSocket) {\n                    pluginSocket.disconnect();\n                    pluginSocket = null;\n                }\n            });\n\n            const sendChat = (msg) => {\n                pluginSocket?.emit('chat', msg);\n            };\n\n            return { message, sendChat };\n        }\n    };</code></pre>\n    \n    \n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-warning font-monospace small\">Socket.IO 客户端 API 参考</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"text-white opacity-75 border-bottom\"><th>方法/属性</th><th>签名</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">ioClient(namespace)</td><td><code>(namespace?: string) =&gt; Socket</code></td><td>连接到指定命名空间。不传参则连接默认命名空间；传入路径必须与后端 registerSocket 的路径一致。示例：ioClient('/plugin/my-plugin/live')</td></tr>\n    <tr><td class=\"font-monospace py-2\">socket.on(event, callback)</td><td><code>(event: string, callback: Function) =&gt; void</code></td><td>监听服务端事件。callback 参数为事件数据。</td></tr>\n    <tr><td class=\"font-monospace py-2\">socket.emit(event, data)</td><td><code>(event: string, data: any) =&gt; void</code></td><td>向服务端发送事件。</td></tr>\n    <tr><td class=\"font-monospace py-2\">socket.disconnect()</td><td><code>() =&gt; void</code></td><td>断开连接。组件卸载时应主动调用此方法清理资源。</td></tr>\n    <tr><td class=\"font-monospace py-2\">socket.connected</td><td>boolean</td><td>是否已连接。只读属性。</td></tr>\n    <tr><td class=\"font-monospace py-2\">socket.id</td><td>string</td><td>Socket 连接 ID。只读属性。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "lifecycle",
                "icon": "fa-heart-pulse",
                "title": "插件生命周期",
                "description": "加载、运行、销毁的完整流程",
                "content": "<section id=\"section-lifecycle\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">插件从安装到卸载会经历多个生命周期阶段。理解这些阶段对于正确管理资源（尤其是清理操作）至关重要。</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"text-white opacity-75 border-bottom\"><th>阶段</th><th>触发条件</th><th>系统行为</th><th>开发者需知</th></tr></thead>\n    <tbody>\n    <tr><td class=\"text-danger font-monospace py-2\"> 发现 (Discover) </td><td> 面板启动或主动调用 discover() </td><td> 扫描 plugins/ 目录，读取 plugin.json 并校验必须字段。检查持久化状态。 </td><td> 确保 <code>plugin.json</code> 格式正确且包含必须字段。 </td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> 加载 (Load) </td><td> 插件已启用且面板启动，或用户手动启用 </td><td> 使用 <code>require()</code> 加载入口文件，创建 <code>api</code> 对象并调用入口函数。 </td><td> 入口必须导出异步函数。可返回含 <code>destroy</code> 方法的对象。 </td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> 运行 (Running) </td><td> 加载成功后 </td><td> 插件的 HTTP 路由、Socket 命名空间、侧边栏项和组件均已注册并可用。 </td><td> 正常提供服务。监听事件、处理请求。 </td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> 卸载 (Unload) </td><td> 用户禁用插件、更新插件或面板关闭时 </td><td> 调用插件返回的 <code>destroy()</code> 方法，并清除 <code>require.cache</code> 缓存。 </td><td>必须在 <code>destroy()</code> 中清理所有资源：关闭子进程、断开连接、清除定时器。</td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> 启用 (Enable) </td><td> 用户在插件管理点击“启用” </td><td> 持久化 <code>_enabled = true</code> 状态，然后触发 Load。 </td><td> 无额外操作，系统自动加载。 </td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> 禁用 (Disable) </td><td> 用户在插件管理点击“禁用” </td><td> 先触发 Unload，然后持久化 <code>_enabled = false</code> 状态。 </td><td> 确保 <code>destroy()</code> 能够正确清理。 </td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> 安装 (Install) </td><td> 用户上传 ZIP </td><td> 解压到 plugins/[id]/，若有旧版则先卸载，重新扫描并自动加载。 </td><td> ZIP 包内可直接包含插件文件，或包含一层同名子目录。 </td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> 更新 (Update) </td><td> 用户上传同 ID 插件的 ZIP </td><td> 等同于覆盖安装：卸载旧版，清空目录，复制新文件，重新加载。 </td><td> 注意：更新时插件原目录被覆盖！请将持久化数据存放在 <code>api.getDataDir()</code> 中。 </td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">生命周期管理最佳实践</span>\n    <span class=\"text-muted opacity-50\">Javascript</span>\n    </div>\n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>module.exports = async function(api) {\n        let intervalId = null;\n        let childProcess = null;\n        const sockets = new Set();\n\n        // 启动定时任务\n        intervalId = setInterval(() => {\n            api.logger.info('执行定时检查...');\n        }, 60000);\n\n        // 启动子进程\n        // childProcess = require('child_process').spawn('some-command');\n\n        // 注册 Socket 命名空间并追踪连接\n        const ns = api.registerSocket('/live', {\n            'join': (socket) => {\n                sockets.add(socket);\n                socket.on('disconnect', () => sockets.delete(socket));\n            }\n        });\n\n        // 必须返回 destroy 方法，确保插件停用时资源被彻底清理\n        return {\n            destroy: async () => {\n                // 1. 清除定时器\n                if (intervalId) {\n                    clearInterval(intervalId);\n                    intervalId = null;\n                }\n\n                // 2. 终止子进程\n                if (childProcess) {\n                    childProcess.kill();\n                    childProcess = null;\n                }\n\n                // 3. 断开所有活跃的 Socket 连接\n                sockets.forEach(s => s.disconnect());\n                sockets.clear();\n\n                api.logger.info('所有资源已彻底清理');\n            }\n        };\n    };</code></pre>\n    \n    \n    </div>\n    </section>"
            },
            {
                "id": "panel-api",
                "icon": "fa-route",
                "title": "面板内置 API 端点参考",
                "description": "插件前端可直接调用的面板后端接口",
                "content": "<section id=\"section-panel-api\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">插件前端通过 <code>api.get/post/put/delete</code> 调用面板内置 API。所有需要认证的接口已自动附加认证信息。带 <code>withInstance</code> 标记的接口会自动附加 <code>instanceId</code> 参数。插件后端路由前缀为 <code>/api/plugins/[插件ID]</code>。</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #ec4899;\"><i class=\"fa-solid fa-server me-2\"></i>服务器控制</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>方法</th><th>端点</th><th>参数</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/server/status</td><td>withInstance</td><td>获取服务器运行状态。返回 <code>{ running: boolean, onlinePlayers: string[] }</code></td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/server/start</td><td>withInstance</td><td>启动服务器。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/server/stop</td><td>withInstance</td><td>停止服务器。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/server/command</td><td>withInstance, body: { command: string }</td><td>发送服务器命令。示例：<code>await api.post('/api/server/command', { command: 'say Hello' })</code></td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/server/icon</td><td>withInstance</td><td>获取服务器图标。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #ec4899;\"><i class=\"fa-solid fa-list me-2\"></i>玩家列表</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>方法</th><th>端点</th><th>参数</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/lists/:type</td><td>withInstance, :type 合法值：<code>'whitelist'</code>、<code>'ops'</code>、<code>'banned-players'</code></td><td>获取玩家列表。返回数组。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/lists/:type</td><td>withInstance, body: { action: 'add'|'remove', name: string }</td><td>修改玩家列表。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #ec4899;\"><i class=\"fa-solid fa-folder me-2\"></i>文件管理</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>方法</th><th>端点</th><th>参数</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/files/list</td><td>withInstance, query: { path: string }</td><td>列出目录内容。</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/files/content</td><td>withInstance, query: { path: string }</td><td>读取文件文本内容。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/files/save</td><td>withInstance, body: { path: string, content: string }</td><td>保存文件内容。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/files/mkdir</td><td>withInstance, body: { path: string }</td><td>创建目录。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/files/create</td><td>withInstance, body: { path: string }</td><td>创建空文件。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/files/rename</td><td>withInstance, body: { oldPath: string, newPath: string }</td><td>重命名/移动文件。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/files/operate</td><td>withInstance, body: { action: 'delete'|'copy'|'move', paths: string[], target?: string }</td><td>批量文件操作。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/files/upload</td><td>withInstance, FormData: files + path</td><td>上传文件。</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/files/download</td><td>withInstance, query: { path: string }</td><td>下载文件。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #ec4899;\"><i class=\"fa-solid fa-cubes me-2\"></i>实例管理</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>方法</th><th>端点</th><th>参数</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/instances/list</td><td>无</td><td>获取所有实例列表。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/instances/create</td><td>body: { id: string, name: string }</td><td>创建实例。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/instances/select</td><td>body: { instanceId: string }</td><td>选择当前管理的实例。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/instances/rename</td><td>body: { instanceId: string, name: string }</td><td>重命名实例。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/instances/delete</td><td>body: { instanceId: string }</td><td>删除实例。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #ec4899;\"><i class=\"fa-solid fa-gear me-2\"></i>面板配置</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>方法</th><th>端点</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/panel/config</td><td>获取面板配置。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/panel/config</td><td>保存面板配置。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/panel/restart</td><td>重启面板。</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/system/version</td><td>获取面板版本号（无需认证）。</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/appearance/config</td><td>获取外观配置。</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/appearance/:type</td><td>获取外观资源。:type 合法值：<code>'logo'</code>、<code>'background'</code>。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #ec4899;\"><i class=\"fa-solid fa-puzzle-piece me-2\"></i>插件系统</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>方法</th><th>端点</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/list</td><td>获取已安装插件列表。</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/sidebar-items</td><td>获取所有插件侧边栏项。</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/components</td><td>获取所有插件组件映射。</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/dashboard-cards</td><td>获取仪表盘卡片列表。</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/translations</td><td>获取所有插件翻译数据。</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/:pluginId/manifest</td><td>获取指定插件的 plugin.json。</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/:pluginId/component/:name</td><td>获取指定插件的组件文件。系统用于动态加载组件。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/plugins/enable</td><td>启用插件。body: { pluginId: string }</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/plugins/disable</td><td>禁用插件。body: { pluginId: string }</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/plugins/upload</td><td>上传安装插件。FormData: plugin (ZIP 文件)。</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/plugins/uninstall</td><td>卸载插件。body: { pluginId: string }</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "css",
                "icon": "fa-palette",
                "title": "CSS 样式类参考",
                "description": "面板预置的 CSS 工具类和组件样式",
                "content": "<section id=\"section-css\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">面板基于 Bootstrap 5 暗色主题构建，同时提供了一些自定义样式类。插件前端组件可直接使用这些类名。</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #f59e0b;\"><i class=\"fa-solid fa-wand-magic-sparkles me-2\"></i>自定义工具类</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>类名</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">.animate-in</td><td>页面进入淡入动画。用于顶层容器。</td></tr>\n    <tr><td class=\"font-monospace py-2\">.animate-fade</td><td>淡入动画变体。</td></tr>\n    <tr><td class=\"font-monospace py-2\">.btn-back</td><td>返回按钮样式。圆形半透明按钮，内含左箭头图标。用法：<code>&lt;button class='btn-back me-3' @click='...'&gt;&lt;i class='fa-solid fa-chevron-left'&gt;&lt;/i&gt;&lt;/button&gt;</code></td></tr>\n    <tr><td class=\"font-monospace py-2\">.page-header</td><td>页面顶部标题区域样式。提供底部间距和对齐。</td></tr>\n    <tr><td class=\"font-monospace py-2\">.dev-code-block</td><td>代码块样式。等宽字体、适当行高。</td></tr>\n    <tr><td class=\"font-monospace py-2\">.log-info / .log-warn / .log-error / .log-system</td><td>日志级别高亮样式。INFO=绿色、WARN=黄色、ERROR=红色、系统=蓝色。</td></tr>\n    <tr><td class=\"font-monospace py-2\">.no-scrollbar</td><td>隐藏滚动条但保留滚动功能。</td></tr>\n    <tr><td class=\"font-monospace py-2\">.tracking-tighter / .tracking-tight / .tracking-wider</td><td>字间距调整。对应 letter-spacing 值。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #f59e0b;\"><i class=\"fa-solid fa-paintbrush me-2\"></i>CSS 变量</h6>\n    <p class=\"small text-muted mb-3\">面板定义了以下 CSS 变量，可用于自定义样式并自动适配暗色/亮色主题：</p>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>变量</th><th>说明</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">--c-surface</td><td>主表面背景色。</td></tr>\n    <tr><td class=\"font-monospace py-2\">--c-surface-elevated</td><td>提升层表面背景色（卡片等）。</td></tr>\n    <tr><td class=\"font-monospace py-2\">--c-border</td><td>边框颜色。</td></tr>\n    <tr><td class=\"font-monospace py-2\">--c-bg-base-rgb</td><td>基础背景色的 RGB 值（用于 rgba）。</td></tr>\n    <tr><td class=\"font-monospace py-2\">--app-sidebar-opacity</td><td>侧边栏透明度。</td></tr>\n    <tr><td class=\"font-monospace py-2\">--app-content-opacity</td><td>内容区透明度。</td></tr>\n    <tr><td class=\"font-monospace py-2\">--app-card-opacity</td><td>卡片透明度。</td></tr>\n    <tr><td class=\"font-monospace py-2\">--app-bg-image</td><td>背景图片 URL。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "tips",
                "icon": "fa-lightbulb",
                "title": "开发技巧",
                "description": "FAQ, Best Practices & Safety",
                "content": "<section id=\"section-tips\" class=\"doc-section mb-5\">\n    \n\n    <div class=\"row g-4\">\n    <div class=\"col-md-6\">\n    <div class=\"card border-0 shadow-sm rounded-4 h-100\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold text-success mb-3\"><i class=\"fa-solid fa-check-circle me-2\"></i> 最佳实践 </h6>\n    <ul class=\"small text-muted mb-0 ps-3 lh-lg\">\n    <li>使用 <code>api.getDataDir()</code> 存放插件私有数据，系统会自动创建目录</li>\n    <li>使用 <code>api.getGlobalDataDir()</code> 存放跨插件共享数据</li>\n    <li>所有 HTTP 路由自动附加认证中间件，无需手动验证</li>\n    <li>组件卸载时必须断开 Socket（在 <code>onUnmounted</code> 中调用 <code>disconnect()</code>）</li>\n    <li>使用 <code>api.logger</code> 而非 <code>console.log</code>，便于日志溯源</li>\n    <li>返回 <code>destroy</code> 方法清理所有资源（定时器、进程、连接）</li>\n    <li>前端使用 <code>api.get/post/put/delete</code>，自动附加认证和实例 ID</li>\n    <li>使用全局的 <code>$t()</code> 函数支持多语言</li>\n    </ul>\n    </div>\n    </div>\n    </div>\n    <div class=\"col-md-6\">\n    <div class=\"card border-0 shadow-sm rounded-4 h-100\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold text-danger mb-3\"><i class=\"fa-solid fa-triangle-exclamation me-2\"></i> 注意事项 </h6>\n    <ul class=\"small text-muted mb-0 ps-3 lh-lg\">\n    <li>插件发布后请勿随意修改 ID，因为它是目录名和 API 路径的一部分</li>\n    <li>更新插件时整个目录会被覆盖，请将持久化数据存放在 <code>data</code> 目录内</li>\n    <li>不要直接修改面板核心文件，仅通过 <code>api</code> 对象提供的接口操作</li>\n    <li>前端组件必须使用 ES Module 格式（<code>export default</code>）</li>\n    <li>后端入口必须导出函数（<code>module.exports = async function(api) {}</code>）</li>\n    <li>Socket 命名空间路径为 <code>/plugin/[插件ID]/[自定义路径]</code>，前端需完整拼接</li>\n    <li>避免在全局作用域创建长连接或定时器，应在入口函数内创建并在 <code>destroy</code> 中清理</li>\n    <li>插件间不要直接通信，应通过全局 Socket 事件或共享数据目录间接交互</li>\n    </ul>\n    </div>\n    </div>\n    </div>\n    </div>\n    </section>"
            }
        ]
    },
    "en": {
        "sections": [
            {
                "id": "intro",
                "icon": "fa-rocket",
                "title": "Quick Start",
                "description": "Create a folder with plugin.json to start.",
                "content": "<section id=\"section-intro\" class=\"doc-section mb-5 animate-in\">\n    \n    \n    <p class=\"text-muted mb-4 lh-lg\">Cloud Language Panel adopts a modular architecture, plugins can deeply intervene in backend logic and frontend UI. Each plugin is an independent directory containing a metadata manifest, backend entry, and frontend resources. Simply compress the directory content into a ZIP when packaging.</p>\n\n    <div class=\"row g-4 mb-4\">\n    <div class=\"col-md-6\">\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">Directory Structure</span>\n    <span class=\"text-muted opacity-50\">Tree</span>\n    </div>\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>my-plugin/\n    ├── plugin.json       # Core manifest file (Required)\n    ├── index.js          # Backend entry (Optional)\n    ├── component/        # Frontend components directory (Optional)\n    │   └── Main.js       # Frontend Vue component\n    └── data/             # Plugin private data (Auto-created)\n    └── ...           # Runtime generated data files</code></pre>\n    \n    </div>\n    </div>\n    <div class=\"col-md-6\">\n    <div class=\"code-block-wrapper h-100 shadow-sm rounded-4 overflow-hidden border\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">plugin.json</span>\n    <span class=\"text-muted opacity-50\">JSON</span>\n    </div>\n    <pre  class=\"p-3 small mb-0 dev-code-block h-100\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>{\n        \"id\": \"my-plugin\",\n        \"name\": {\n            \"zh\": \"我的插件\",\n            \"en\": \"My Plugin\"\n        },\n        \"version\": \"1.0.0\",\n        \"author\": \"Antigravity\",\n        \"description\": {\n            \"zh\": \"一个示例插件\",\n            \"en\": \"An example plugin\"\n        },\n        \"icon\": \"fa-rocket\",\n        \"color\": \"#4caf50\",\n        \"main\": \"index.js\",\n        \"defaultEnabled\": true,\n        \"permissions\": [\"file_system\"]\n    }</code></pre>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "manifest",
                "icon": "fa-file-code",
                "title": "plugin.json Reference",
                "description": "Field types, requirements, defaults and valid values",
                "content": "<section id=\"section-manifest\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">plugin.json is the metadata manifest file for the plugin, located in the root directory. It is the only required file.</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small text-uppercase text-secondary tracking-wider\" style=\"font-size: 0.75rem;\">Field Details</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead>\n    <tr class=\"text-white opacity-75 border-bottom\">\n    <th>Field</th>\n    <th>Type</th>\n    <th>Required</th>\n    <th>Default</th>\n    <th>Description</th>\n    </tr>\n    </thead>\n    <tbody>\n    <tr><td class=\"text-info font-monospace py-2\">id</td><td>string</td><td class=\"text-danger\">Yes</td><td>—</td><td>Unique plugin identifier. Can only contain lowercase letters, numbers, hyphens and underscores.</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">name</td><td>string | object</td><td class=\"text-danger\">Yes</td><td>—</td><td>Plugin display name. Two formats:<br><strong>String</strong>: <code>&quot;My Plugin&quot;</code> (language-agnostic);<br><strong>Object</strong>: <code>{ &quot;zh&quot;: &quot;我的插件&quot;, &quot;en&quot;: &quot;My Plugin&quot; }</code> (multilingual, recommended). Fallback: current lang → en → zh → first value.</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">version</td><td>string</td><td class=\"text-danger\">Yes</td><td>—</td><td>Version number, e.g., 1.0.0.</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">description</td><td>string | object</td><td>No</td><td>—</td><td>Function description. Same format as name, supports string or multilingual object. Example: <code>{ &quot;zh&quot;: &quot;一个示例插件&quot;, &quot;en&quot;: &quot;An example plugin&quot; }</code></td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">author</td><td>string</td><td>No</td><td>—</td><td>Author info.</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">icon</td><td>string</td><td>No</td><td>\"fa-puzzle-piece\"</td><td>Icon class name.</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">color</td><td>string</td><td>No</td><td>\"primary\"</td><td>Theme color.</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">main</td><td>string</td><td>No</td><td>\"index.js\"</td><td>Backend entry.</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">defaultEnabled</td><td>boolean</td><td>No</td><td>true</td><td>Enabled by default.</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">official</td><td>boolean</td><td>No</td><td>false</td><td>Official tag.</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">permissions</td><td>string[]</td><td>No</td><td>[]</td><td>Permissions list.</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">homepage</td><td>string</td><td>No</td><td>\"\"</td><td>Homepage URL.</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">license</td><td>string</td><td>No</td><td>\"\"</td><td>License identifier.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "dependencies",
                "icon": "fa-npm",
                "title": "NPM Dependencies",
                "description": "",
                "content": "<section id=\"section-dependencies\" class=\"doc-section mb-5\">\n    \n    \n    <p class=\"text-muted mb-4 lh-lg\">The plugin system deeply integrates NPM dependency management. You only need to declare <code>dependencies</code> in <code>plugin.json</code>, and the panel will automatically handle the installation logic when installing or updating the plugin.</p>\n\n    <div class=\"row g-4\">\n    <div class=\"col-md-6\">\n    <div class=\"card border-0 shadow-sm rounded-4 h-100\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold text-warning mb-3\"><i class=\"fa-solid fa-cloud-arrow-down me-2\"></i>Smart Install Process</h6>\n    \n    <ul class=\"small text-muted mb-0 ps-3 lh-lg\">\n    <li>Supports <code>pnpm</code> and <code>npm</code> auto-fallback</li>\n    <li>Built-in mirror source polling for high success rate</li>\n    <li>Physical dependency isolation between plugins</li>\n    </ul>\n    </div>\n    </div>\n    </div>\n    <div class=\"col-md-6\">\n    <div class=\"card border-0 shadow-sm rounded-4 h-100\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold text-info mb-3\"><i class=\"fa-solid fa-shield-halved me-2\"></i>Module Isolation</h6>\n    \n    <p class=\"text-muted mb-4 lh-lg\">The panel implements Scoped Require for each plugin. Each plugin's <code>require()</code> calls are anchored to its own directory, avoiding version conflicts.</p>\n    </div>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "backend",
                "icon": "fa-server",
                "title": "Backend & API Reference",
                "description": "",
                "content": "<section id=\"section-backend\" class=\"doc-section mb-5\">\n    \n    \n    <p class=\"text-muted mb-4 lh-lg\">Plugin backend scripts must export an async function, and the system automatically injects the <code>api</code> object. This object encapsulates all operable interfaces. Running in a Node.js environment, besides core packages like <code>express</code> and <code>fs-extra</code>, it's recommended to declare and use private packages via <code>plugin.json</code>'s <code>dependencies</code>. Each plugin has an independent module loading context.</p>\n\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">Entry Function Signature</span>\n    <span class=\"text-muted opacity-50\">Javascript</span>\n    </div>\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>// index.js — Plugin Backend Entry\n    module.exports = async function(api) {\n        // api object contains all properties and methods\n\n        // Optional: Return an object containing a destroy method\n        // destroy() is called automatically when the plugin is disabled or uninstalled\n        return {\n            destroy: async () => {\n                // Clean up resources: close processes, disconnect, clear timers, etc.\n            }\n        };\n    };</code></pre>\n    \n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-circle-info me-2 text-info\"></i>api Object Read-only Properties</h5>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead>\n    <tr class=\"text-white opacity-75 border-bottom\">\n    <th>Property</th>\n    <th>Type</th>\n    <th>Description</th>\n    </tr>\n    </thead>\n    <tbody>\n    <tr><td class=\"text-info font-monospace py-2\">api.id</td><td>string</td><td>Plugin ID, matches id in plugin.json. Example: 'my-plugin'</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">api.manifest</td><td>object</td><td>Complete plugin.json manifest. Includes internal fields: _dir (absolute path), _enabled (boolean), _installed (boolean).</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">api.io</td><td>SocketIO.Server</td><td>Panel Socket.IO server instance. Can be used for global broadcasting. Namespace: /plugin/[PluginID]/[CustomPath].</td></tr>\n    <tr><td class=\"text-info font-monospace py-2\">api.context</td><td>object</td><td>Context object injected by the panel, containing runtime environment info (see context section below).</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-box-open me-2 text-info\"></i>api.context Context Object</h5>\n    <p class=\"text-muted mb-3 small\">Access via <code>api.context</code>, or destructure directly: <code>const { instancesDir, baseDir } = api.context;</code>. Available fields:</p>\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead>\n    <tr class=\"text-white opacity-75 border-bottom\">\n    <th>Field</th>\n    <th>Type</th>\n    <th>Description</th>\n    </tr>\n    </thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">instancesDir</td><td>string</td><td>Absolute path to instances root directory. Each sub-directory name is the instance ID.</td></tr>\n    <tr><td class=\"font-monospace py-2\">baseDir</td><td>string</td><td>Absolute path to panel base directory. Example: '/opt/mc-panel'. Root workspace.</td></tr>\n    <tr><td class=\"font-monospace py-2\">dataDir</td><td>string</td><td>Absolute path to panel global data directory. Stores configs, Java, etc.</td></tr>\n    <tr><td class=\"font-monospace py-2\">globalBackupDir</td><td>string</td><td>Absolute path to global backups directory. Stores cross-instance backup ZIP files.</td></tr>\n    <tr><td class=\"font-monospace py-2\">pluginsDir</td><td>string</td><td>Absolute path to plugins installation directory. Example: '/opt/mc-panel/plugins'.</td></tr>\n    <tr><td class=\"font-monospace py-2\">getConfig</td><td>function</td><td>Function to get panel config. Usage: api.context.getConfig(). See api.getConfig() details below.</td></tr>\n    <tr><td class=\"font-monospace py-2\">instancesState</td><td>Map&lt;string, object&gt;</td><td>Map of instance states. Key is instance ID. Contains: process, logHistory, onlinePlayers, detectedVersion, etc.</td></tr>\n    <tr><td class=\"font-monospace py-2\">appendLog</td><td>function</td><td>Function to append logs to instance console. Signature: appendLog(instanceId: string, message: string).</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-code me-2 text-info\"></i>Full api Method Reference</h5>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.registerRoutes(prefix, setupFn)</h6>\n    <p class=\"small text-muted mb-2\">Register HTTP API routes. All routes automatically add authentication middleware, final path is /api/plugins/[PluginID][prefix].</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Param</th><th>Type</th><th>Required</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">prefix</td><td>string</td><td class=\"text-danger\">Yes</td><td>Route prefix. Recommended to start with /. Auto-completed if missing.</td></tr>\n    <tr><td class=\"font-monospace\">setupFn</td><td>express.Router | function</td><td class=\"text-danger\">Yes</td><td>Two formats:<br>1. <strong>express.Router instance</strong> (Recommended): Pass a configured Router.<br>2. <strong>Function</strong>: Pass a function that returns a Router. Auto-called by system.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>// Option 1: Direct Router (Recommended)\n    const router = express.Router();\n    router.get('/hello', (req, res) => res.json({ msg: 'Hello' }));\n    router.post('/data', (req, res) => res.json({ received: req.body }));\n    api.registerRoutes('/', router);\n    // Frontend call: GET /api/plugins/my-plugin/hello\n\n    // Option 2: Function\n    api.registerRoutes('/api', () => {\n        const router = express.Router();\n        router.get('/status', (req, res) => res.json({ ok: true }));\n        return router;\n    });\n    // Frontend call: GET /api/plugins/my-plugin/api/status\n\n    // File upload example (requires multer)\n    const upload = multer({ dest: path.join(DATA_DIR, 'tmp_uploads') });\n    router.post('/upload', upload.single('file'), (req, res) => {\n        const file = req.file;\n        res.json({ success: true, filename: file.originalname });\n    });</code></pre>\n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.registerPublicRoutes(prefix, setupFn)</h6>\n    <p class=\"small text-muted mb-2\">Register public HTTP API routes. These do NOT require authentication, suitable for external integrations. Final path: /api/public/plugins/[PluginID][prefix].</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Param</th><th>Type</th><th>Required</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">prefix</td><td>string</td><td class=\"text-danger\">Yes</td><td>Route prefix. Final path = /api/public/plugins/[PluginID] + prefix.</td></tr>\n    <tr><td class=\"font-monospace\">setupFn</td><td>express.Router | function</td><td class=\"text-danger\">Yes</td><td>Same as registerRoutes. Strongly recommended to implement custom API Key verification.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>const router = express.Router();\n    router.get('/status', (req, res) => {\n        // External call: GET /api/public/plugins/my-plugin/status\n        res.json({ online: true, version: '1.0.0' });\n    });\n    api.registerPublicRoutes('/', router);</code></pre>\n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.registerSocket(namespace, handlers)</h6>\n    <p class=\"small text-muted mb-2\">Register WebSocket namespace and event handlers. Returns Socket.IO Namespace instance. Namespace path is /plugin/[PluginID][namespace].</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Param</th><th>Type</th><th>Required</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">namespace</td><td>string</td><td class=\"text-danger\">Yes</td><td>Namespace path. Recommended to start with /. Example: '/live'.</td></tr>\n    <tr><td class=\"font-monospace\">handlers</td><td>object</td><td class=\"text-danger\">Yes</td><td>Event handler mapping object. Key is event name, value is handler function. Signature: (socket, ...args) => void.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-2\"><strong>Returns</strong>: Socket.IO Namespace instance. Use <code>ns.emit('event', data)</code> to broadcast.</p>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>const ns = api.registerSocket('/live', {\n        'chat': (socket, message) => {\n            api.logger.info('Received chat:', message);\n            ns.emit('chat_response', { echo: message });\n        },\n        'join_room': (socket, roomId) => {\n            socket.join(roomId);\n            socket.emit('joined', { roomId });\n        }\n    });\n\n    // Backend broadcast example\n    ns.emit('notification', { msg: 'System Notification' });</code></pre>\n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.registerSidebarItem(item)</h6>\n    <p class=\"small text-muted mb-2\">Register frontend sidebar navigation item. Appears in instance sidebar or global dropdown based on location.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Field</th><th>Type</th><th>Required</th><th>Default</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">item.id</td><td>string</td><td class=\"text-danger\">Yes</td><td>—</td><td>Unique identifier for sidebar item. Suggested format: '[PluginID]-[FeatureName]'.</td></tr>\n    <tr><td class=\"font-monospace\">item.labelKey</td><td>string</td><td class=\"text-danger\">Yes</td><td>—</td><td>i18n translation key. Translated via $t(item.labelKey). Examples: 'plugins.my-plugin.title'.</td></tr>\n    <tr><td class=\"font-monospace\">item.icon</td><td>string</td><td>Yes</td><td>—</td><td>FontAwesome 6 Free solid icon class (without fa-solid prefix).</td></tr>\n    <tr><td class=\"font-monospace\">item.color</td><td>string</td><td>No</td><td>—</td><td>Icon color. Supports CSS color keywords or HEX values.</td></tr>\n    <tr><td class=\"font-monospace\">item.view</td><td>string</td><td class=\"text-danger\">Yes</td><td>—</td><td>View name. Sets store.view on click. MUST match registerComponent name parameter!</td></tr>\n    <tr><td class=\"font-monospace\">item.location</td><td>string</td><td>No</td><td><code>\"instance\"</code></td><td>Display location. Valid values: 'instance' (instance sidebar only), 'global' (global dropdown), 'both'.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>// Instance-level sidebar item (default, only visible inside instance)\n    api.registerSidebarItem({\n        id: 'backup-manager',\n        labelKey: 'plugins.my-plugin.title',\n        icon: 'fa-box-archive',\n        color: '#f1c40f',\n        view: 'plugin-mc-panel-plugin-backup-main',\n        location: 'instance'\n    });\n\n    // Global-level sidebar item (accessible without selecting instance)\n    api.registerSidebarItem({\n        id: 'frp-manager',\n        labelKey: 'sidebar.frp_manager',\n        icon: 'fa-network-wired',\n        color: '#6366f1',\n        view: 'frp-manager',\n        location: 'global'\n    });</code></pre>\n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.registerComponent(name, componentPath)</h6>\n    <p class=\"small text-muted mb-2\">Register frontend Vue component. System automatically loads it via dynamic import and registers it globally.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Param</th><th>Type</th><th>Required</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">name</td><td>string</td><td class=\"text-danger\">Yes</td><td>Component registration name. MUST match registerSidebarItem view value to render properly.</td></tr>\n    <tr><td class=\"font-monospace\">componentPath</td><td>string</td><td class=\"text-danger\">Yes</td><td>Component file path, relative to plugin root. Must be an ES Module exporting Vue 3 options via export default.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-2\"><strong>Component Loading Mechanism</strong>: System serves component file via <code>/api/plugins/[PluginID]/component/[ComponentName]</code>, frontend dynamically loads via <code>import()</code>. Component must use <code>export default</code>.</p>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>api.registerComponent('plugin-my-plugin-main', 'component/Main.js');\n    // Component file component/Main.js must use export default:\n    // export default { template: '...', setup() { ... } }</code></pre>\n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.registerDashboardCard(name, componentName)</h6>\n    <p class=\"small text-muted mb-2\">Register dashboard visualization cards. Cards appear at the top of the instance list page, suitable for global system status or summary data.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Param</th><th>Type</th><th>Required</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">name</td><td>string</td><td class=\"text-danger\">Yes</td><td>Unique identifier for the card. Example: 'CPUStatus', 'MemoryUsage'.</td></tr>\n    <tr><td class=\"font-monospace\">componentName</td><td>string</td><td class=\"text-danger\">Yes</td><td>Associated Vue component name. MUST be registered via registerComponent first.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>// 1. Register component first\n    api.registerComponent('SystemStatusCard', 'component/SystemStatusCard.js');\n\n    // 2. Mount component to dashboard card slot\n    api.registerDashboardCard('GlobalStatus', 'SystemStatusCard');</code></pre>\n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getDataDir()</h6>\n    <p class=\"small text-muted mb-2\">Get plugin private data directory absolute path. Created automatically if missing.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Item</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td>Params</td><td>None</td></tr>\n    <tr><td>Returns</td><td>string — Absolute path to plugin private data dir. Format: [PluginDir]/data.</td></tr>\n    <tr><td>Side Effects</td><td>Created automatically via fs.ensureDirSync() if missing</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>const dataDir = api.getDataDir();\n    const configPath = path.join(dataDir, 'config.json');\n    await fs.writeJson(configPath, { setting: 'value' }, { spaces: 2 });</code></pre>\n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getGlobalDataDir()</h6>\n    <p class=\"small text-muted mb-2\">Get panel global data directory path. Suitable for cross-plugin shared or persistent data.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Item</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td>Params</td><td>None</td></tr>\n    <tr><td>Returns</td><td>string — Absolute path to global data dir. Example: '/opt/mc-panel/data'.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>const globalDir = api.getGlobalDataDir();\n    const myDataDir = path.join(globalDir, 'my-plugin');\n    await fs.ensureDir(myDataDir);</code></pre>\n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getInstancesDir()</h6>\n    <p class=\"small text-muted mb-2\">Get MC instances root directory path. Equivalent to api.context.instancesDir.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Item</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td>Params</td><td>None</td></tr>\n    <tr><td>Returns</td><td>string — Absolute path to instances root dir. Example: '/opt/mc-panel/instances'.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getBaseDir()</h6>\n    <p class=\"small text-muted mb-2\">Get panel base directory path. Equivalent to api.context.baseDir.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Item</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td>Params</td><td>None</td></tr>\n    <tr><td>Returns</td><td>string — Absolute path to base directory. Example: '/opt/mc-panel'.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getActiveInstanceId()</h6>\n    <p class=\"small text-muted mb-2\">Get the currently active instance ID. Reads activeInstanceId from instances.json, returns 'default' if not configured. Useful when a plugin needs to know which instance the user is managing.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Item</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td>Params</td><td>None</td></tr>\n    <tr><td>Returns</td><td>string — Current active instance ID. Example: 'my-server', 'default'.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getInstanceDir(instanceId?)</h6>\n    <p class=\"small text-muted mb-2\">Get the absolute directory path for a specified instance. If instanceId is omitted, uses the active instance. Looks up instance config in instances.json and builds the full path, ensuring correct paths in multi-instance environments.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Item</th><th>Type</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td>instanceId</td><td>string?</td><td>Optional. Instance ID, defaults to active instance.</td></tr>\n    <tr><td>Returns</td><td>string | null</td><td>Absolute instance directory path. Example: '/opt/mc-panel/instances/my-server'. Returns null if instance not found.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <h6 class=\"fw-bold mb-2 small text-muted\">Usage Example</h6>\n    <pre class=\"bg-dark bg-opacity-10 rounded-3 p-3 small mb-0\"><code>// 在插件路由中使用\nconst withInstance = (req, res, next) => {\n    const instanceId = req.query.instanceId || api.getActiveInstanceId();\n    const instDir = api.getInstanceDir(instanceId);\n    if (!instDir) return res.status(404).json({ error: 'Instance not found' });\n    req.instDir = instDir;\n    next();\n};\n\n// 获取当前实例的数据库路径\nconst dbPath = path.join(api.getInstanceDir(), 'easyauth.db');</code></pre>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.getConfig()</h6>\n    <p class=\"small text-muted mb-2\">Get full panel configuration object including current runtime parameters.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Item</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td>Params</td><td>None</td></tr>\n    <tr><td>Returns</td><td>object — Panel config object (see field details below)</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <h6 class=\"fw-bold mb-2 small text-muted\">Return Object Fields</h6>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Field</th><th>Type</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">isSetup</td><td>boolean</td><td>Whether panel setup (2FA) is complete.</td></tr>\n    <tr><td class=\"font-monospace py-2\">sessionSecret</td><td>string</td><td>Session encryption secret.</td></tr>\n    <tr><td class=\"font-monospace py-2\">sessionTimeout</td><td>number</td><td>Session timeout (days).</td></tr>\n    <tr><td class=\"font-monospace py-2\">githubProxy</td><td>string</td><td>GitHub proxy. Empty means direct connection. Example: 'https://mirror.example.com'</td></tr>\n    <tr><td class=\"font-monospace py-2\">modrinthApi</td><td>string</td><td>Modrinth API base URL. Default: 'https://api.modrinth.com/v2'</td></tr>\n    <tr><td class=\"font-monospace py-2\">port</td><td>number</td><td>Panel listening port. Default: 3000</td></tr>\n    <tr><td class=\"font-monospace py-2\">consoleInfoPosition</td><td>string</td><td>Console info position. Values: 'top', 'sidebar', 'hide'.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>const config = api.getConfig();\n    if (config.githubProxy) {\n        const proxiedUrl = originalUrl.replace('https://github.com', config.githubProxy);\n    }</code></pre>\n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-info font-monospace small\">api.logger</h6>\n    <p class=\"small text-muted mb-2\">Plugin-specific logger. Automatically prefixes [Plugin:PluginName] for easy tracing.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Method</th><th>Signature</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">api.logger.info</td><td><code>(...args: any[]) => void</code></td><td>Output info level log. Format: [Plugin:PluginName] Message</td></tr>\n    <tr><td class=\"font-monospace py-2\">api.logger.warn</td><td><code>(...args: any[]) => void</code></td><td>Output warning level logs.</td></tr>\n    <tr><td class=\"font-monospace py-2\">api.logger.error</td><td><code>(...args: any[]) => void</code></td><td>Output error level log.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>api.logger.info('Plugin initialized successfully');\n    // Output: [Plugin:MyPlugin] Plugin initialized successfully\n\n    api.logger.warn('Configuration not found, using defaults');\n    api.logger.error('Failed to connect:', error.message);</code></pre>\n    \n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-file-code me-2 text-info\"></i>Full Backend Example</h5>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">index.js — Full Backend Example</span>\n    <span class=\"text-muted opacity-50\">Javascript</span>\n    </div>\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>const fs = require('fs-extra');\n    const path = require('path');\n    const express = require('express');\n\n    module.exports = async function(api) {\n        const { registerRoutes, context } = api;\n        const { instancesDir, dataDir, getConfig } = context;\n        const DATA_DIR = api.getDataDir();\n        const CONFIG_FILE = path.join(DATA_DIR, 'config.json');\n\n        const readConfig = () => {\n            try { return fs.readJsonSync(CONFIG_FILE); }\n            catch (e) { return { items:[] }; }\n        };\n        const writeConfig = (config) => {\n            fs.writeJsonSync(CONFIG_FILE, config, { spaces: 2 });\n        };\n\n        const router = express.Router();\n\n        router.get('/items', (req, res) => {\n            const config = readConfig();\n            res.json(config.items);\n        });\n\n        router.post('/items', (req, res) => {\n            const { name, value } = req.body;\n            if (!name) return res.status(400).json({ error: 'name is required' });\n            const config = readConfig();\n            config.items.push({ id: Date.now().toString(), name, value: value || '' });\n            writeConfig(config);\n            res.json({ success: true });\n        });\n\n        api.registerRoutes('/', router);\n\n        const ns = api.registerSocket('/live', {\n            'message': (socket, data) => ns.emit('broadcast', data)\n        });\n\n        api.registerSidebarItem({\n            id: 'my-plugin-main',\n            labelKey: 'plugins.my_plugin.title',\n            icon: 'fa-rocket',\n            color: '#6366f1',\n            view: 'my-plugin-view',\n            location: 'instance'\n        });\n\n        api.registerComponent('my-plugin-view', 'component/Main.js');\n\n        api.logger.info('Plugin initialized');\n\n        return {\n            destroy: async () => {\n                api.logger.info('Plugin is being unloaded, cleaning up...');\n            }\n        };\n    };</code></pre>\n    \n    </div>\n    </section>"
            },
            {
                "id": "frontend",
                "icon": "fa-display",
                "title": "Frontend Guide",
                "description": "Build plugin interface using Vue 3",
                "content": "<section id=\"section-frontend\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">Frontend uses Vue 3 components (ES Module). Registered via <code>api.registerComponent()</code>, auto-loaded dynamically. Component must use <code>export default</code>.</p>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-puzzle-piece me-2 text-success\"></i> Available Imports </h5>\n    <p class=\"text-muted mb-3 small\">The following imports are available in frontend components:</p>\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"text-white opacity-75 border-bottom\"><th>Import Statement</th><th>Source</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">import { ref, reactive, computed, onMounted, onUnmounted, watch, getCurrentInstance } from '/js/vue.esm-browser.js'</td><td>Vue 3</td><td>Vue 3 Composition API. Available exports: <code>ref</code>, <code>reactive</code>, <code>computed</code>, <code>watch</code>, etc.</td></tr>\n    <tr><td class=\"font-monospace py-2\">import { store } from '/js/store.js'</td><td>Panel</td><td>Global reactive state. Vue 3 reactive() object. All properties are reactive. See store reference table below.</td></tr>\n    <tr><td class=\"font-monospace py-2\">import { api } from '/js/api.js'</td><td>Panel</td><td>Authenticated API requests based on axios. Automatically attaches instanceId. See API reference table below.</td></tr>\n    <tr><td class=\"font-monospace py-2\">import { showToast, openModal, formatLog, waitForPanel, uploadFileWithChunk, isLargeFile } from '/js/utils.js'</td><td>Panel</td><td>Collection of utility functions. See reference table below.</td></tr>\n    <tr><td class=\"font-monospace py-2\">import { socket } from '/js/socket.js'</td><td>Panel</td><td>Socket.IO client instance (default namespace). Used to listen for global panel events.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-code me-2 text-success\"></i> Frontend Component Template </h5>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">component/Main.js — Full Frontend Component Template</span>\n    <span class=\"text-muted opacity-50\">Javascript</span>\n    </div>\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>import { ref, onMounted, onUnmounted, getCurrentInstance } from '/js/vue.esm-browser.js';\n    import { api } from '/js/api.js';\n    import { store } from '/js/store.js';\n    import { showToast, openModal } from '/js/utils.js';\n\n    export default {\n        template: \\`\n        &lt;div class=\"animate-in\"&gt;\n        &lt;div class=\"page-header d-flex justify-content-between align-items-center mb-4\"&gt;\n        &lt;div class=\"d-flex align-items-center\"&gt;\n        &lt;button @click=\"store.view = store.prevView || 'instance-manager'\" class=\"btn-back me-3\"&gt;\n        &lt;i class=\"fa-solid fa-chevron-left\"&gt;&lt;/i&gt;\n        &lt;/button&gt;\n        &lt;div&gt;\n        &lt;h3 class=\"m-0 fw-bold d-flex align-items-center\"&gt;\n        &lt;i class=\"fa-solid fa-rocket me-3 text-primary\"&gt;&lt;/i&gt;\n        &lt;span&gt;plugins.my_plugin.title&lt;/span&gt;\n        &lt;/h3&gt;\n        &lt;/div&gt;\n        &lt;/div&gt;\n        &lt;button class=\"btn btn-primary rounded-pill px-4\" @click=\"loadData\"&gt;\n        &lt;i class=\"fa-solid fa-refresh me-1\"&gt;&lt;/i&gt;Refresh\n        &lt;/button&gt;\n        &lt;/div&gt;\n        &lt;div v-if=\"loading\" class=\"text-center py-5\"&gt;\n        &lt;div class=\"spinner-border text-primary\"&gt;&lt;/div&gt;\n        &lt;/div&gt;\n        &lt;div v-else&gt;\n        &lt;!-- Your Content --&gt;\n        &lt;/div&gt;\n        &lt;/div&gt;\n        \\`,\n        setup() {\n            const { proxy } = getCurrentInstance();\n            const $t = proxy.$t;\n            const pluginApiBase = '/api/plugins/my-plugin';\n            const loading = ref(false);\n            const items = ref([]);\n\n            const loadData = async () => {\n                try {\n                    loading.value = true;\n                    const res = await api.get(\\`\\${pluginApiBase}/items\\`);\n                    items.value = res.data;\n                } catch (e) {\n                    showToast(e.response?.data?.error || e.message, 'danger');\n                } finally {\n                    loading.value = false;\n                }\n            };\n\n            onMounted(() => { loadData(); });\n            return { store, loading, items, loadData };\n        }\n    };</code></pre>\n    \n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-database me-2 text-success\"></i> Full store Global State Reference </h5>\n    <p class=\"text-muted mb-3 small\">Imported via <code>import { store } from '/js/store.js'</code>. Vue 3 reactive object, all properties are reactive. Can be directly read and modified.</p>\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead>\n    <tr class=\"text-white opacity-75 border-bottom\"><th>Property</th><th>Type</th><th>Description</th></tr>\n    </thead>\n    <tbody>\n    <tr><td class=\"text-success font-monospace py-2\">store.auth</td><td>object</td><td>Auth state object. Fields: <br><code>loggedIn</code> (boolean); <code>isSetup</code> (boolean) 2FA setup; <code>qrCode</code> (string) QR Data URL; <code>secret</code> (string) 2FA secret; <code>token</code> (string).</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.isSetup</td><td>boolean</td><td>Whether the panel setup is complete.</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.lang</td><td>string</td><td>Current UI language. Values: <code>'zh'</code> (Chinese), <code>'en'</code> (English).</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.onlinePlayers</td><td>string[]</td><td>List of online player names for the current instance. Example: <code>['Steve', 'Alex']</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.stats</td><td>object</td><td>System and server status object. Fields: <br><code>cpu</code> (string) CPU usage %, e.g., <code>'45.2'</code>; <code>mem</code> (object) memory info: <code>{ total: '15.9' (GB), used: '8.3' (GB), percentage: '52.3' (%) }</code>; <code>mc</code> (object) MC server info: <code>{ online: 5, maxPlayers: 20, port: '25565', motd: 'A Minecraft Server' }</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.isRunning</td><td>boolean</td><td>Whether current MC server is running.</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.hasBackupMod</td><td>boolean</td><td>Whether current instance has backup mod.</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.hasEasyAuth</td><td>boolean</td><td>Whether the current instance has EasyAuth mod installed.</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.hasVoicechat</td><td>boolean</td><td>Whether current instance has voicechat mod.</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.logs</td><td>string[]</td><td>Current instance console log array. Max 1000 lines. Each as plain text.</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.view</td><td>string</td><td>Current view name. Set this to switch pages. Built-in views: <code>'instance-manager'</code>, <code>'dashboard'</code>, <code>'properties'</code>, <code>'mods'</code>, <code>'modrinth'</code>, <code>'files'</code>, <code>'backups'</code>, <code>'easyauth'</code>, <code>'voicechat'</code>, <code>'players'</code>, <code>'java'</code>, <code>'about'</code>, <code>'plugins'</code>, <code>'panel-settings'</code>. Plugin views use registerSidebarItem view value.</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.prevView</td><td>string</td><td>Previous view name. Used for back buttons. Example: <code>store.view = store.prevView</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.consoleInfoPosition</td><td>string</td><td>Console info panel position. Valid values: 'top' (default), 'sidebar', 'hide'.</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.currentInstanceId</td><td>string|null</td><td>ID of current instance. <code>null</code> on list page. Examples: <code>'default'</code>, <code>'survival'</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.instanceList</td><td>object[]</td><td>List of all instances. Each contains: <code>id</code>, <code>name</code>, <code>dir</code>, <code>hasBackupMod</code>, <code>backupStrategy</code>, <code>isRunning</code>, etc.</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.javaInstallations</td><td>object[]</td><td>List of installed Java. Each: <code>id</code>; <code>featureVersion</code> (e.g., 17, 21); <code>path</code> (absolute); <code>source</code> ('local'|'panel').</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.customLogoUrl</td><td>string</td><td>Custom Logo URL. Empty string uses default. Format: '/api/appearance/logo' or full URL.</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.customBgUrl</td><td>string</td><td>Custom background URL. Empty for default. Format: <code>'/api/appearance/background'</code> or full URL.</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.task</td><td>object</td><td>Global task progress object (ProgressModal component). Fields: <code>visible</code> (boolean); <code>title</code> (string); <code>message</code> (string); <code>subMessage</code> (string); <code>percent</code> (number 0-100); <code>speed</code> (bytes/sec, 0=none); <code>canCancel</code> (boolean); <code>onCancel</code> (function|null).</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.dashboardCards</td><td>object[]</td><td>Dashboard card list. Registered via api.registerDashboardCard. Each: <code>name</code> (string), <code>componentName</code> (string).</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.pluginSidebarItems</td><td>object[]</td><td>List of plugin sidebar items. Each: <code>id</code>, <code>labelKey</code>, <code>icon</code>, <code>color</code>, <code>view</code>, <code>location</code>, <code>pluginId</code>, <code>component</code>.</td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">store.pluginComponents</td><td>object</td><td>Map of plugin components. Key: name. Value: <code>{ pluginId, path }</code>. Auto-loaded via <code>store.view</code>.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-globe me-2 text-success\"></i> Frontend API Reference </h5>\n    <p class=\"text-muted mb-3 small\">Imported via <code>import { api } from '/js/api.js'</code>. Based on axios, automatically attaches <code>instanceId</code> and auth info.</p>\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"text-white opacity-75 border-bottom\"><th>Method</th><th>Signature</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"text-success font-monospace py-2\">api.get</td><td><code>(url: string, config?: AxiosRequestConfig) =&gt; Promise&lt;AxiosResponse&gt;</code></td><td>Send GET request. <code>config</code> is optional. Automatically attaches <code>instanceId</code> query parameter. Example: <code>const res = await api.get('/api/plugins/my-plugin/items');</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">api.post</td><td><code>(url: string, data?: any, config?: AxiosRequestConfig) =&gt; Promise&lt;AxiosResponse&gt;</code></td><td>Send POST request. <code>data</code> is body (auto JSON); or multipart if <code>FormData</code>. Auto-attaches <code>instanceId</code> to body. Example: <code>await api.post('/api/plugins/my-plugin/items', { name: 'test' });</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">api.put</td><td><code>(url: string, data?: any, config?: AxiosRequestConfig) =&gt; Promise&lt;AxiosResponse&gt;</code></td><td>Send PUT request. Params same as <code>api.post</code>. Example: <code>await api.put('/api/plugins/my-plugin/config', { key: 'value' });</code></td></tr>\n    <tr><td class=\"text-success font-monospace py-2\">api.delete</td><td><code>(url: string, config?: AxiosRequestConfig) =&gt; Promise&lt;AxiosResponse&gt;</code></td><td>Send DELETE request. Automatically attaches <code>instanceId</code> query parameter. Example: <code>await api.delete('/api/plugins/my-plugin/items/123');</code></td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-0 mt-3\"><strong>Request Interceptor</strong>: All requests auto-attach <code>store.currentInstanceId</code>. GET/DELETE attach to URL query; POST/PUT attach to body (FormData uses <code>append</code>, JSON uses spread). Data via <code>res.data</code>.</p>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-wrench me-2 text-success\"></i> Utility Functions Reference </h5>\n    <p class=\"text-muted mb-3 small\">Import via <code>import { ... } from '/js/utils.js'</code>.</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-success font-monospace small\">showToast(msg, type, params)</h6>\n    <p class=\"small text-muted mb-2\">Show global toast. Auto-translates if msg is a translation key. Disappears after 3s.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Param</th><th>Type</th><th>Required</th><th>Default</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">msg</td><td>string</td><td class=\"text-danger\">Yes</td><td>—</td><td>Toast message or i18n key. Auto-translates if key (e.g., 'common.saved'); else shows original. Examples: 'Success', 'common.error'</td></tr>\n    <tr><td class=\"font-monospace\">type</td><td>string</td><td>No</td><td><code>\"success\"</code></td><td>Toast type, determines color and icon. Valid values: 'success', 'danger', 'warning', 'info'.</td></tr>\n    <tr><td class=\"font-monospace\">params</td><td>object</td><td>No</td><td><code>{}</code></td><td>Translation parameters object. Used to replace placeholders in the template when msg is a translation key.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>showToast('Saved Successfully');                    // Success toast (green)\n    showToast('Operation Failed', 'danger');           // Error toast (red)\n    showToast('Check Config', 'warning');\n    showToast('Processing', 'info');            // Info toast (blue)\n    showToast('common.saved', 'success');      // Use translation key\n    showToast('common.welcome', 'info', { name: 'Admin' }); // With translation params</code></pre>\n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-success font-monospace small\">openModal(opts)</h6>\n    <p class=\"small text-muted mb-2\">Open global modal. Supports confirm, input, select modes. Handles nesting.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Field</th><th>Type</th><th>Required</th><th>Default</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">opts.title</td><td>string</td><td>No</td><td><code>\"确认\"</code></td><td>Modal title. Example: 'Delete Confirmation'.</td></tr>\n    <tr><td class=\"font-monospace\">opts.message</td><td>string</td><td>No</td><td><code>\"\"</code></td><td>Modal body message. Supports HTML.</td></tr>\n    <tr><td class=\"font-monospace\">opts.mode</td><td>string</td><td>No</td><td><code>\"confirm\"</code></td><td>Modal mode. Valid values: 'confirm', 'input', 'select'.</td></tr>\n    <tr><td class=\"font-monospace\">opts.inputValue</td><td>string</td><td>No</td><td><code>\"\"</code></td><td>Input box default value. Only valid when mode is 'input'.</td></tr>\n    <tr><td class=\"font-monospace\">opts.placeholder</td><td>string</td><td>No</td><td><code>\"\"</code></td><td>Input box placeholder text. Only valid when mode is 'input'.</td></tr>\n    <tr><td class=\"font-monospace\">opts.options</td><td>Array&lt;string | {label: string, value: any}&gt;</td><td>No</td><td><code>[]</code></td><td>Options list. Only valid when mode is 'select'. Two formats:<br><strong>String array</strong>: <code>['OptionA', 'OptionB']</code>, callback receives string;<br><strong>Object array</strong>: <code>[{label: 'Display Text', value: 'actual_value'}]</code>, callback receives value.</td></tr>\n    <tr><td class=\"font-monospace\">opts.suffix</td><td>string</td><td>No</td><td><code>\"\"</code></td><td>Input suffix text. Only valid when mode is 'input'. Displayed right of input, commonly for units (e.g., 'seconds', 'MB').</td></tr>\n    <tr><td class=\"font-monospace\">opts.callback</td><td>function</td><td>No</td><td><code>null</code></td><td>Confirm callback. Signature:<br>mode: 'confirm' → <code>() =&gt; void</code>;<br>mode: 'input' → <code>(inputValue: string) =&gt; void</code>;<br>mode: 'select' → <code>(selectedValue: string) =&gt; void</code>.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>// Confirm Mode\n    openModal({\n        title: \"Delete Confirmation\",\n        message: 'Are you sure you want to delete this? This cannot be undone.',\n        mode: 'confirm',\n        callback: () => { showToast('Deleted'); }\n    });\n\n    // Input mode (with suffix and default value)\n    openModal({\n        title: \"Set Interval\",\n        message: 'Enter auto-backup interval:',\n        mode: 'input',\n        inputValue: \"30\",\n        placeholder: 'Enter number',\n        suffix: 'minutes',\n        callback: (val) => {\n            if (val) showToast('Interval set to: ' + val + ' minutes');\n        }\n    });\n\n    // Select Mode — String array\n    openModal({\n        title: \"Select Backup Policy\",\n        message: 'Please select backup method:',\n        mode: 'select',\n        options:[\"Panel Backup\", \"Mods Backup\", \"Manual Backup\"],\n        callback: (choice) => { showToast(\"Selected: \" + choice); }\n    });\n\n    // Select Mode — Object array (label for display, value for callback)\n    openModal({\n        title: \"Select Game Mode\",\n        message: 'Choose player game mode:',\n        mode: 'select',\n        inputValue: 'survival',\n        options: [\n            { label: 'Survival', value: 'survival' },\n            { label: 'Creative', value: 'creative' },\n            { label: 'Adventure', value: 'adventure' },\n            { label: 'Spectator', value: 'spectator' }\n        ],\n        callback: (val) => { sendCmd('gamemode ' + val + ' Steve'); }\n    });</code></pre>\n    \n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-success font-monospace small\">formatLog(log)</h6>\n    <p class=\"small text-muted mb-2\">Format MC server logs with HTML highlighting for INFO/WARN/ERROR tags.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Param</th><th>Type</th><th>Required</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">log</td><td>string</td><td class=\"text-danger\">Yes</td><td>Raw log text. Example: '[12:00:00 INFO]: Server started'</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-0\"><strong>Returns</strong>：string — Formatted HTML string。<code>[INFO]</code> → <code>&lt;span class=\"log-info\"&gt;INFO&lt;/span&gt;</code>；<code>[WARN]</code> → <code>&lt;span class=\"log-warn\"&gt;WARN&lt;/span&gt;</code>；<code>[ERROR]</code> → <code>&lt;span class=\"log-error\"&gt;ERROR&lt;/span&gt;</code>；<code>[System]</code> → <code>&lt;span class=\"log-system\"&gt;[System]&lt;/span&gt;</code>。Also escapes < to &lt;.</p>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-success font-monospace small\">waitForPanel(targetPort)</h6>\n    <p class=\"small text-muted mb-2\">Wait for panel to come back online. Used after restart, polls until responsive.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Params</th><th>Type</th><th>Required</th><th>Default</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">targetPort</td><td>string|number|null</td><td>No</td><td><code>null</code></td><td>Target port. If provided, polls that port; if null, polls current page API.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-0\"><strong>Returns</strong>: Promise&lt;void&gt; — Resolves when panel recovers. Initial wait 1.5s, then polls every 1s, timeout 2s per poll.</p>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-success font-monospace small\">uploadFileWithChunk(file, options)</h6>\n    <p class=\"small text-muted mb-2\">Multipart upload for files ≥ 100MB. Returns null if < 100MB.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Field</th><th>Type</th><th>Required</th><th>Default</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">file</td><td>File</td><td class=\"text-danger\">Yes</td><td>—</td><td>File object to upload (Browser File API).</td></tr>\n    <tr><td class=\"font-monospace\">options.initUrl</td><td>string</td><td class=\"text-danger\">Yes</td><td>—</td><td>Upload init endpoint. POST request. Should return { uploadId: string }.</td></tr>\n    <tr><td class=\"font-monospace\">options.uploadUrl</td><td>string</td><td>No</td><td><code>\"/api/files/chunk/upload\"</code></td><td>Chunk upload API endpoint. POST request, sends FormData.</td></tr>\n    <tr><td class=\"font-monospace\">options.completeUrl</td><td>string</td><td class=\"text-danger\">Yes</td><td>—</td><td>Upload complete endpoint. POST request, sends { uploadId }.</td></tr>\n    <tr><td class=\"font-monospace\">options.cancelUrl</td><td>string</td><td>No</td><td><code>\"/api/files/chunk/cancel\"</code></td><td>Upload cancellation API endpoint. Automatically called on failure.</td></tr>\n    <tr><td class=\"font-monospace\">options.fieldName</td><td>string</td><td>No</td><td><code>\"chunk\"</code></td><td>Field name of the chunk file in FormData.</td></tr>\n    <tr><td class=\"font-monospace\">options.extraInitData</td><td>object</td><td>No</td><td><code>{}</code></td><td>Extra data for initialization request. Merged into initUrl request body.</td></tr>\n    <tr><td class=\"font-monospace\">options.onProgress</td><td>function</td><td>No</td><td><code>() =&gt; {}</code></td><td>Progress callback. Signature: <code>(uploadedBytes: number, totalBytes: number, chunkIndex: number, totalChunks: number) =&gt; void</code>。</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-0\"><strong>Returns</strong>: Promise<object|null> — null if < 100MB; response data if ≥ 100MB. Chunk size 10MB. Auto-cancels on failure.</p>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-success font-monospace small\">isLargeFile(file)</h6>\n    <p class=\"small text-muted mb-2\">Check if file is large (≥ 100MB). Used to decide whether to use multipart upload.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Params</th><th>Type</th><th>Required</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">file</td><td>File</td><td class=\"text-danger\">Yes</td><td>Browser File object.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <p class=\"small text-muted mb-0\"><strong>Returns</strong>: boolean — true if ≥ 100MB (use uploadFileWithChunk); false otherwise.</p>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "vue-options",
                "icon": "fa-cubes",
                "title": "Vue Component Options & Built-in Components",
                "description": "Component declaration, sub-component registration, reusable built-in components",
                "content": "<section id=\"section-vue-options\" class=\"doc-section mb-5\">\n    \n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-file-code me-2\" style=\"color: #8b5cf6;\"></i>Component Options Object Fields</h5>\n    <p class=\"text-muted mb-3 small\">Frontend component files must use <code>export default {}</code>. Available fields:</p>\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"text-white opacity-75 border-bottom\"><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">template</td><td>string</td><td class=\"text-danger\">Yes</td><td>Component HTML template string. Use ES6 template literals. Supports Vue 3 template syntax.</td></tr>\n    <tr><td class=\"font-monospace py-2\">setup()</td><td>function</td><td class=\"text-danger\">Yes</td><td>Composition API entry. Returns object with properties accessible in template. Must return all reactive vars and methods used in template.</td></tr>\n    <tr><td class=\"font-monospace py-2\">components</td><td>object</td><td>No</td><td>Register sub-components. Key: PascalCase name, Value: imported component. Use kebab-case in template. Example: <code>components: { Avatar }</code> → <code>&lt;avatar&gt;</code></td></tr>\n    <tr><td class=\"font-monospace py-2\">props</td><td>object</td><td>No</td><td>Component props definition. Short: <code>props: { name: String }</code>; Full: <code>props: { name: { type: String, required: true, default: '' } }</code>.</td></tr>\n    <tr><td class=\"font-monospace py-2\">emits</td><td>string[]</td><td>No</td><td>Declare events. Example: <code>emits: ['update', 'delete']</code>. Trigger via setup's second param: <code>emit('update', newValue)</code>.</td></tr>\n    <tr><td class=\"font-monospace py-2\">name</td><td>string</td><td>No</td><td>Component name. Used for recursion and DevTools. Example: <code>name: 'MyPluginView'</code></td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-puzzle-piece me-2\" style=\"color: #8b5cf6;\"></i>Getting $t Translation Function in setup()</h5>\n    <p class=\"text-muted mb-3 small\">Use <code>$t('key')</code> directly in templates. In <code>setup()</code>, get it via <code>getCurrentInstance()</code>:</p>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>import { getCurrentInstance } from '/js/vue.esm-browser.js';\n\nexport default {\n    setup() {\n        const { proxy } = getCurrentInstance();\n        const $t = proxy.$t;\n\n        // 在 JS 逻辑中使用翻译\n        const title = $t('plugins.my-plugin.title');\n        showToast($t('common.success'));\n\n        // ...\n    }\n};</code></pre>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-boxes-stacked me-2\" style=\"color: #8b5cf6;\"></i>Built-in Reusable Components</h5>\n    <p class=\"text-muted mb-3 small\">The panel provides built-in components that plugins can import and use. Register via <code>components</code> field.</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 small\" style=\"color: #8b5cf6;\"><i class=\"fa-solid fa-user me-2\"></i>Avatar — Player Avatar</h6>\n    <p class=\"small text-muted mb-2\">Auto-detects skin source (official/LittleSkin), displays player avatar with pixel-art CSS cropping.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Import</th><th>Description</th></tr></thead>\n    <tbody><tr><td class=\"font-monospace\">import Avatar from '/js/components/Avatar.js'</td><td>Player avatar component</td></tr></tbody>\n    </table>\n    </div>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Props</th><th>Type</th><th>Required</th><th>Default</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">player</td><td>string</td><td class=\"text-danger\">Yes</td><td>—</td><td>Player name.</td></tr>\n    <tr><td class=\"font-monospace\">size</td><td>number</td><td>No</td><td>64</td><td>Avatar size in pixels. Common: 24 (list), 64 (card).</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>import Avatar from '/js/components/Avatar.js';\n\nexport default {\n    components: { Avatar },\n    template: \\`\n        &lt;div&gt;\n            &lt;!-- 大头像 --&gt;\n            &lt;avatar :player=\"playerName\" :size=\"64\"&gt;&lt;/avatar&gt;\n            &lt;!-- 列表小头像 --&gt;\n            &lt;avatar :player=\"p\" :size=\"24\" class=\"me-2\"&gt;&lt;/avatar&gt;\n        &lt;/div&gt;\n    \\`,\n    setup() {\n        const playerName = ref('Steve');\n        return { playerName };\n    }\n};</code></pre>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 small\" style=\"color: #8b5cf6;\"><i class=\"fa-solid fa-list me-2\"></i>CustomSelect — Custom Select Dropdown</h6>\n    <p class=\"small text-muted mb-2\">Feature-rich custom select with search, keyboard nav, auto-positioning. Uses Teleport to body.</p>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Import</th><th>Description</th></tr></thead>\n    <tbody><tr><td class=\"font-monospace\">import CustomSelect from '/js/components/CustomSelect.js'</td><td>Custom select component</td></tr></tbody>\n    </table>\n    </div>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Props</th><th>Type</th><th>Required</th><th>Default</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">modelValue</td><td>any</td><td>No</td><td>''</td><td>Current selected value. Supports v-model.</td></tr>\n    <tr><td class=\"font-monospace\">options</td><td>Array&lt;string | {label: string, value: any}&gt;</td><td>No</td><td>[]</td><td>Options list. Supports string array and object array (same as openModal).</td></tr>\n    <tr><td class=\"font-monospace\">placeholder</td><td>string</td><td>No</td><td>''</td><td>Placeholder text.</td></tr>\n    <tr><td class=\"font-monospace\">disabled</td><td>boolean</td><td>No</td><td>false</td><td>Whether disabled.</td></tr>\n    <tr><td class=\"font-monospace\">size</td><td>string</td><td>No</td><td>''</td><td>Size. Valid: <code>''</code> (default), <code>'sm'</code>, <code>'lg'</code>.</td></tr>\n    <tr><td class=\"font-monospace\">searchable</td><td>boolean</td><td>No</td><td>false</td><td>Enable search filtering.</td></tr>\n    <tr><td class=\"font-monospace\">width</td><td>string</td><td>No</td><td>''</td><td>Custom width. CSS value, e.g., '200px', '100%'.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"table-responsive mb-3\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Events</th><th>Params</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">update:modelValue</td><td>value: any</td><td>Fired when selection changes. For v-model.</td></tr>\n    <tr><td class=\"font-monospace\">change</td><td>value: any</td><td>Fired on selection change. For watching changes.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>import CustomSelect from '/js/components/CustomSelect.js';\n\nexport default {\n    components: { CustomSelect },\n    template: \\`\n        &lt;div&gt;\n            &lt;!-- 基础用法 --&gt;\n            &lt;custom-select\n                v-model=\"selectedMode\"\n                :options=\"modeOptions\"\n                placeholder=\"选择模式\"\n            /&gt;\n\n            &lt;!-- 带搜索 --&gt;\n            &lt;custom-select\n                v-model=\"selectedPlayer\"\n                :options=\"store.onlinePlayers\"\n                searchable\n                placeholder=\"搜索玩家\"\n                size=\"sm\"\n            /&gt;\n        &lt;/div&gt;\n    \\`,\n    setup() {\n        const selectedMode = ref('');\n        const modeOptions = [\n            { label: '生存模式', value: 'survival' },\n            { label: '创造模式', value: 'creative' }\n        ];\n        const selectedPlayer = ref('');\n        return { selectedMode, modeOptions, selectedPlayer, store };\n    }\n};</code></pre>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 small\" style=\"color: #8b5cf6;\"><i class=\"fa-solid fa-spinner me-2\"></i>ProgressModal — Global Progress Overlay</h6>\n    <p class=\"small text-muted mb-2\">Fullscreen frosted-glass progress overlay, globally registered. Control via <code>store.task</code>.</p>\n    <div class=\"code-block-wrapper rounded-3 overflow-hidden border\">\n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface); overflow-x: auto; white-space: pre;\"><code>// 显示进度遮罩\nstore.task.visible = true;\nstore.task.title = '导出数据';\nstore.task.message = '正在处理...';\nstore.task.percent = 50;\nstore.task.speed = 0;\nstore.task.canCancel = true;\nstore.task.onCancel = () => {\n    store.task.visible = false;\n    showToast('已取消', 'warning');\n};\n\n// 更新进度\nstore.task.percent = 80;\nstore.task.message = '即将完成...';\n\n// 完成后关闭\nstore.task.percent = 100;\nstore.task.message = '完成！';\nsetTimeout(() => { store.task.visible = false; }, 1000);</code></pre>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "i18n",
                "icon": "fa-globe",
                "title": "Internationalization (i18n)",
                "description": "",
                "content": "<section id=\"section-i18n\" class=\"doc-section mb-5\">\n    \n    \n    <p class=\"text-muted mb-4 lh-lg\">The panel supports independent internationalization for plugins. Plugins can create a <code>locales/</code> directory in their root to place JSON format translation files. The system will automatically load and merge these translations on the frontend.</p>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-folder-tree me-2 text-info\"></i>Directory Structure</h5>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>my-plugin/\n    ├── locales/\n    │   ├── zh.json    # Chinese Translation\n    │   └── en.json    # English Translation\n    ├── component/\n    │   └── Main.js\n    └── plugin.json</code></pre>\n    \n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-file-code me-2 text-info\"></i>Translation Example (zh.json)</h5>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>{\n        \"title\": \"My Plugin\",\n        \"description\": \"This is a test plugin\",\n        \"buttons\": {\n            \"start\": \"Start Task\",\n            \"stop\": \"Stop Task\"\n        }\n    }</code></pre>\n    \n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-tag me-2 text-info\"></i>Namespace Rules</h5>\n    \n    <p class=\"text-muted mb-4 lh-lg\">To avoid conflicts between plugins, the system automatically mounts all translations of a plugin under the <code>plugins.[pluginId]</code> namespace.</p>\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    \n    <ul class=\"small text-muted mb-0 ps-3 lh-lg\">\n    <li><i class=\"fa-solid fa-check text-success me-2\"></i>If plugin ID is <code>my-plugin</code> and translation has <code>\"title\": \"Hello\"</code></li>\n    <li><i class=\"fa-solid fa-check text-success me-2\"></i>Frontend call key: <code>plugins.my-plugin.title</code></li>\n    <li><i class=\"fa-solid fa-check text-success me-2\"></i>Sidebar <code>labelKey</code>: <code>plugins.my-plugin.title</code></li>\n    </ul>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-terminal me-2 text-info\"></i>Frontend Usage</h5>\n    \n    <p class=\"text-muted mb-4 lh-lg\">Use the global <code>$t()</code> function in Vue templates:</p>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>&lt;template&gt;\n    &lt;div&gt;\n    &lt;h3&gt;plugins.my-plugin.title&lt;/h3&gt;\n    &lt;button&gt;plugins.my-plugin.buttons.start&lt;/button&gt;\n    &lt;/div&gt;\n    &lt;/template&gt;</code></pre>\n    </div>\n    </section>"
            },
            {
                "id": "socket",
                "icon": "fa-plug",
                "title": "Socket.IO Communication",
                "description": "Real-time Bidirectional Data Interaction",
                "content": "<section id=\"section-socket\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">Panel has built-in Socket.IO. Plugins can register namespaces for real-time communication (logs, status, etc.).</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small text-uppercase text-warning tracking-wider\" style=\"font-size: 0.75rem;\">Panel Global Events (Default Namespace)</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead>\n    <tr class=\"text-white opacity-75 border-bottom\"><th>Event</th><th>Data Structure</th><th>Description</th></tr>\n    </thead>\n    <tbody>\n    <tr><td class=\"text-warning font-monospace py-2\">status</td><td>{ isRunning: boolean }</td><td>Running state change of current active instance.</td></tr>\n    <tr><td class=\"text-warning font-monospace py-2\">status:{instanceId}</td><td>{ isRunning: boolean }</td><td>Status change of a specific instance.</td></tr>\n    <tr><td class=\"text-warning font-monospace py-2\">players_update</td><td>string[]</td><td>Online player list update for current active instance.</td></tr>\n    <tr><td class=\"text-warning font-monospace py-2\">players_update:{instanceId}</td><td>string[]</td><td>Online player list update for specified instance.</td></tr>\n    <tr><td class=\"text-warning font-monospace py-2\">system_stats</td><td>object</td><td>System stats update. Includes: cpu, mem, mc info.</td></tr>\n    <tr><td class=\"text-warning font-monospace py-2\">instances_update</td><td>object[]</td><td>Instance list update. Format matches store.instanceList.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <h5 class=\"fw-bold mb-3\"><i class=\"fa-solid fa-code me-2 text-warning\"></i>Plugin Custom Socket Namespace</h5>\n    <p class=\"text-muted mb-3 small\">Plugin backend creates an independent Socket namespace via api.registerSocket(namespace, handlers). Frontend connection method:</p>\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border mb-4\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">Plugin Socket Communication Example</span>\n    <span class=\"text-muted opacity-50\">Javascript</span>\n    </div>\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>// === Backend index.js ===\n    const ns = api.registerSocket('/live', {\n        'chat': (socket, message) => {\n            api.logger.info('Chat received:', message);\n            ns.emit('chat_response', { echo: message, from: socket.id });\n        },\n        'request_data': (socket, params) => {\n            socket.emit('data_response', { result: 'processed', params });\n        }\n    });\n\n    // Broadcast to all connected clients\n    // ns.emit('notification', { msg: 'System Maintenance Notice' });\n\n    // === Frontend component/Main.js ===\n    import { ref, onMounted, onUnmounted } from '/js/vue.esm-browser.js';\n\n    export default {\n        template: '&lt;div&gt;{{ message }}&lt;/div&gt;',\n        setup() {\n            const message = ref('');\n            let pluginSocket = null;\n\n            onMounted(async () => {\n                // Dynamically import Socket.IO client\n                const { io: ioClient } = await import('/socket.io/socket.io.esm.min.js');\n\n                // Option 1: Connect to plugin custom namespace\n                pluginSocket = ioClient('/plugin/my-plugin/live');\n                pluginSocket.on('chat_response', (data) => {\n                    message.value = data.echo;\n                });\n                pluginSocket.on('notification', (data) => {\n                    message.value = data.msg;\n                });\n\n                // Option 2: Use default namespace (listen to global events)\n                // pluginSocket = ioClient();\n                // pluginSocket.on('system_stats', (data) => { ... });\n            });\n\n            onUnmounted(() => {\n                if (pluginSocket) {\n                    pluginSocket.disconnect();\n                    pluginSocket = null;\n                }\n            });\n\n            const sendChat = (msg) => {\n                pluginSocket?.emit('chat', msg);\n            };\n\n            return { message, sendChat };\n        }\n    };</code></pre>\n    \n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-2 text-warning font-monospace small\">Socket.IO Client API Reference</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"text-white opacity-75 border-bottom\"><th>Method/Prop</th><th>Signature</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">ioClient(namespace)</td><td><code>(namespace?: string) =&gt; Socket</code></td><td>Connect to namespace. Default if no param; else must match backend registerSocket path. Example: ioClient('/plugin/my-plugin/live')</td></tr>\n    <tr><td class=\"font-monospace py-2\">socket.on(event, callback)</td><td><code>(event: string, callback: Function) =&gt; void</code></td><td>Listen for server-side events. callback param gets event data.</td></tr>\n    <tr><td class=\"font-monospace py-2\">socket.emit(event, data)</td><td><code>(event: string, data: any) =&gt; void</code></td><td>Send events to the server.</td></tr>\n    <tr><td class=\"font-monospace py-2\">socket.disconnect()</td><td><code>() =&gt; void</code></td><td>Disconnect. Should be proactively called when component unmounts.</td></tr>\n    <tr><td class=\"font-monospace py-2\">socket.connected</td><td>boolean</td><td>Whether connected. Read-only.</td></tr>\n    <tr><td class=\"font-monospace py-2\">socket.id</td><td>string</td><td>Socket connection ID. Read-only property.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "lifecycle",
                "icon": "fa-heart-pulse",
                "title": "Plugin Lifecycle",
                "description": "Full Lifecycle: Load, Run, Destroy",
                "content": "<section id=\"section-lifecycle\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">Plugins go through several lifecycle stages from installation to uninstallation. Understanding these stages is crucial for proper resource management.</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"text-white opacity-75 border-bottom\"><th>Phase</th><th>Trigger</th><th>System Action</th><th>Developer Notice</th></tr></thead>\n    <tbody>\n    <tr><td class=\"text-danger font-monospace py-2\"> Discover </td><td> Panel starts or discover() is called </td><td> Scan plugins/ directory, read plugin.json in each subdirectory. Verify required fields. Check persistence state. </td><td> Ensure <code>plugin.json</code> format is correct with required fields. </td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> Load </td><td> Plugin enabled and panel starts, or user enables manually </td><td> Load entry via <code>require()</code>, create <code>api</code> object and call entry function. </td><td> Entry must export an async function. Can return an object with a <code>destroy</code> method. </td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> Running </td><td> After successful loading </td><td> HTTP routes, Sockets, Sidebar items, and Components are registered and available. </td><td> Serving normally. Listening to events, handling requests. </td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> Unload </td><td> User disables plugin, updates plugin, or panel closes </td><td> Call <code>destroy()</code> if exists. Clear <code>require.cache</code>. </td><td>Must clean up all resources in <code>destroy()</code>: close processes, disconnect, clear timers.</td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> Enable </td><td> User clicks 'Enable' in plugin manager </td><td> Persists <code>_enabled = true</code> state, then calls Load. </td><td> No extra action, auto-loaded by system. </td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> Disable </td><td> User clicks 'Disable' in plugin manager </td><td> Triggers Unload first, then persists <code>_enabled = false</code>. </td><td> Ensure <code>destroy()</code> cleans up correctly. </td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> Install </td><td> User uploads ZIP </td><td> Unzip to plugins/[id]/. Uninstall old version if exists. Rescan and auto-load. </td><td> ZIP can contain plugin files directly or in a subdirectory. </td></tr>\n    <tr><td class=\"text-danger font-monospace py-2\"> Update </td><td> User uploads ZIP with same ID </td><td> Same as installation: uninstall old, empty dir, copy new, reload. </td><td> Warning: plugin dir is overwritten! Store persistent data in <code>api.getDataDir()</code>. </td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"code-block-wrapper shadow-sm rounded-4 overflow-hidden border\">\n    <div class=\"code-header d-flex justify-content-between px-3 py-2 small bg-dark bg-opacity-10 border-bottom\">\n    <span class=\"fw-bold\">Lifecycle Management Best Practices</span>\n    <span class=\"text-muted opacity-50\">Javascript</span>\n    </div>\n    \n    \n    <pre  class=\"p-3 small mb-0 dev-code-block\" style=\"background: var(--c-surface-elevated); overflow-x: auto; white-space: pre;\"><code>module.exports = async function(api) {\n        let intervalId = null;\n        let childProcess = null;\n        const sockets = new Set();\n\n        // Start periodic tasks\n        intervalId = setInterval(() => {\n            api.logger.info('Periodic check...');\n        }, 60000);\n\n        // Start child process\n        // childProcess = require('child_process').spawn('some-command');\n\n        // Register Socket namespace and track connections\n        const ns = api.registerSocket('/live', {\n            'join': (socket) => {\n                sockets.add(socket);\n                socket.on('disconnect', () => sockets.delete(socket));\n            }\n        });\n\n        // Return destroy method to ensure resource cleanup\n        return {\n            destroy: async () => {\n                // 1. Clear timers\n                if (intervalId) {\n                    clearInterval(intervalId);\n                    intervalId = null;\n                }\n\n                // 2. Kill child process\n                if (childProcess) {\n                    childProcess.kill();\n                    childProcess = null;\n                }\n\n                // 3. Disconnect all Socket connections\n                sockets.forEach(s => s.disconnect());\n                sockets.clear();\n\n                api.logger.info('All resources cleaned up');\n            }\n        };\n    };</code></pre>\n    \n    </div>\n    </section>"
            },
            {
                "id": "panel-api",
                "icon": "fa-route",
                "title": "Panel Built-in API Endpoints Reference",
                "description": "Panel backend endpoints callable from plugin frontend",
                "content": "<section id=\"section-panel-api\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">Plugin frontend calls panel APIs via <code>api.get/post/put/delete</code>. Auth is auto-attached. Endpoints marked <code>withInstance</code> auto-attach <code>instanceId</code>. Plugin backend routes are prefixed with <code>/api/plugins/[PluginID]</code>.</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #ec4899;\"><i class=\"fa-solid fa-server me-2\"></i>Server Control</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Method</th><th>Endpoint</th><th>Params</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/server/status</td><td>withInstance</td><td>Get server status. Returns <code>{ running: boolean, onlinePlayers: string[] }</code></td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/server/start</td><td>withInstance</td><td>Start server.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/server/stop</td><td>withInstance</td><td>Stop server.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/server/command</td><td>withInstance, body: { command: string }</td><td>Send server command. Example: <code>await api.post('/api/server/command', { command: 'say Hello' })</code></td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/server/icon</td><td>withInstance</td><td>Get server icon.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #ec4899;\"><i class=\"fa-solid fa-list me-2\"></i>Player Lists</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Method</th><th>Endpoint</th><th>Params</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/lists/:type</td><td>withInstance, :type valid: <code>'whitelist'</code>, <code>'ops'</code>, <code>'banned-players'</code></td><td>Get player list. Returns array.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/lists/:type</td><td>withInstance, body: { action: 'add'|'remove', name: string }</td><td>Modify player list.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #ec4899;\"><i class=\"fa-solid fa-folder me-2\"></i>File Management</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Method</th><th>Endpoint</th><th>Params</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/files/list</td><td>withInstance, query: { path: string }</td><td>List directory contents.</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/files/content</td><td>withInstance, query: { path: string }</td><td>Read file text content.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/files/save</td><td>withInstance, body: { path: string, content: string }</td><td>Save file content.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/files/mkdir</td><td>withInstance, body: { path: string }</td><td>Create directory.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/files/create</td><td>withInstance, body: { path: string }</td><td>Create empty file.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/files/rename</td><td>withInstance, body: { oldPath: string, newPath: string }</td><td>Rename/move file.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/files/operate</td><td>withInstance, body: { action, paths, target }</td><td>Batch file operations.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/files/upload</td><td>withInstance, FormData: files + path</td><td>Upload files.</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/files/download</td><td>withInstance, query: { path: string }</td><td>Download file.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #ec4899;\"><i class=\"fa-solid fa-cubes me-2\"></i>Instance Management</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Method</th><th>Endpoint</th><th>Params</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/instances/list</td><td>None</td><td>Get all instances list.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/instances/create</td><td>body: { id: string, name: string }</td><td>Create instance.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/instances/select</td><td>body: { instanceId: string }</td><td>Select current instance.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/instances/rename</td><td>body: { instanceId, name }</td><td>Rename instance.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/instances/delete</td><td>body: { instanceId }</td><td>Delete instance.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #ec4899;\"><i class=\"fa-solid fa-gear me-2\"></i>Panel Configuration</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/panel/config</td><td>Get panel config.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/panel/config</td><td>Save panel config.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/panel/restart</td><td>Restart panel.</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/system/version</td><td>Get panel version (no auth required).</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/appearance/config</td><td>Get appearance config.</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/appearance/:type</td><td>Get appearance resource. :type valid: <code>'logo'</code>, <code>'background'</code>.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #ec4899;\"><i class=\"fa-solid fa-puzzle-piece me-2\"></i>Plugin System</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/list</td><td>Get installed plugins list.</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/sidebar-items</td><td>Get all plugin sidebar items.</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/components</td><td>Get all plugin component mappings.</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/dashboard-cards</td><td>Get dashboard cards list.</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/translations</td><td>Get all plugin translations.</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/:pluginId/manifest</td><td>Get plugin manifest.</td></tr>\n    <tr><td class=\"font-monospace\">GET</td><td class=\"font-monospace\">/api/plugins/:pluginId/component/:name</td><td>Get plugin component file. Used for dynamic loading.</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/plugins/enable</td><td>Enable plugin. body: { pluginId }</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/plugins/disable</td><td>Disable plugin. body: { pluginId }</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/plugins/upload</td><td>Upload and install plugin. FormData: plugin (ZIP file).</td></tr>\n    <tr><td class=\"font-monospace\">POST</td><td class=\"font-monospace\">/api/plugins/uninstall</td><td>Uninstall plugin. body: { pluginId }</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "css",
                "icon": "fa-palette",
                "title": "CSS Style Classes Reference",
                "description": "Panel preset CSS utility classes and component styles",
                "content": "<section id=\"section-css\" class=\"doc-section mb-5\">\n    \n    <p class=\"text-muted mb-4 lh-lg\">Panel is built on Bootstrap 5 dark theme with custom style classes. Plugin components can use these directly.</p>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #f59e0b;\"><i class=\"fa-solid fa-wand-magic-sparkles me-2\"></i>Custom Utility Classes</h6>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Class</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">.animate-in</td><td>Page enter fade-in animation. Use on top-level container.</td></tr>\n    <tr><td class=\"font-monospace py-2\">.animate-fade</td><td>Fade-in animation variant.</td></tr>\n    <tr><td class=\"font-monospace py-2\">.btn-back</td><td>Back button style. Circular semi-transparent button with left arrow. Usage: <code>&lt;button class='btn-back'&gt;...&lt;/button&gt;</code></td></tr>\n    <tr><td class=\"font-monospace py-2\">.page-header</td><td>Page header area style. Provides bottom spacing and alignment.</td></tr>\n    <tr><td class=\"font-monospace py-2\">.dev-code-block</td><td>Code block style. Monospace font, proper line height.</td></tr>\n    <tr><td class=\"font-monospace py-2\">.log-info / .log-warn / .log-error / .log-system</td><td>Log level highlight. INFO=green, WARN=yellow, ERROR=red, system=blue.</td></tr>\n    <tr><td class=\"font-monospace py-2\">.no-scrollbar</td><td>Hide scrollbar but keep scroll functionality.</td></tr>\n    <tr><td class=\"font-monospace py-2\">.tracking-tighter / .tracking-tight / .tracking-wider</td><td>Letter-spacing adjustments.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n\n    <div class=\"card border-0 shadow-sm rounded-4 mb-4\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold mb-3 small\" style=\"color: #f59e0b;\"><i class=\"fa-solid fa-paintbrush me-2\"></i>CSS Variables</h6>\n    <p class=\"small text-muted mb-3\">Panel defines these CSS variables, auto-adapting to dark/light themes:</p>\n    <div class=\"table-responsive\">\n    <table class=\"table table-sm dev-table mb-0 small text-muted\">\n    <thead><tr class=\"border-bottom\"><th>Variable</th><th>Description</th></tr></thead>\n    <tbody>\n    <tr><td class=\"font-monospace py-2\">--c-surface</td><td>Main surface background.</td></tr>\n    <tr><td class=\"font-monospace py-2\">--c-surface-elevated</td><td>Elevated surface background (cards, etc.).</td></tr>\n    <tr><td class=\"font-monospace py-2\">--c-border</td><td>Border color.</td></tr>\n    <tr><td class=\"font-monospace py-2\">--c-bg-base-rgb</td><td>Base background RGB values (for rgba).</td></tr>\n    <tr><td class=\"font-monospace py-2\">--app-sidebar-opacity</td><td>Sidebar opacity.</td></tr>\n    <tr><td class=\"font-monospace py-2\">--app-content-opacity</td><td>Content area opacity.</td></tr>\n    <tr><td class=\"font-monospace py-2\">--app-card-opacity</td><td>Card opacity.</td></tr>\n    <tr><td class=\"font-monospace py-2\">--app-bg-image</td><td>Background image URL.</td></tr>\n    </tbody>\n    </table>\n    </div>\n    </div>\n    </div>\n    </section>"
            },
            {
                "id": "tips",
                "icon": "fa-lightbulb",
                "title": "Dev Tips",
                "description": "FAQ, Best Practices & Safety",
                "content": "<section id=\"section-tips\" class=\"doc-section mb-5\">\n    \n\n    <div class=\"row g-4\">\n    <div class=\"col-md-6\">\n    <div class=\"card border-0 shadow-sm rounded-4 h-100\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold text-success mb-3\"><i class=\"fa-solid fa-check-circle me-2\"></i> Best Practices </h6>\n    <ul class=\"small text-muted mb-0 ps-3 lh-lg\">\n    <li>Use <code>api.getDataDir()</code> for private data; auto-created.</li>\n    <li>Use <code>api.getGlobalDataDir()</code> for data shared across plugins.</li>\n    <li>Auth middleware auto-attached to all HTTP routes.</li>\n    <li>Always disconnect Socket connections on unmount (call <code>disconnect()</code> in <code>onUnmounted</code>)</li>\n    <li>Use <code>api.logger</code> instead of <code>console.log</code> for better log traceability</li>\n    <li>Return <code>destroy</code> to clean up all resources (timers, procs, conns).</li>\n    <li>Use <code>api.get/post/put/delete</code> on frontend; auth/instanceId auto-attached.</li>\n    <li>Use the global <code>$t()</code> function for multi-language support</li>\n    </ul>\n    </div>\n    </div>\n    </div>\n    <div class=\"col-md-6\">\n    <div class=\"card border-0 shadow-sm rounded-4 h-100\" style=\"background: var(--c-surface-elevated); border: 1px solid rgba(255,255,255,0.05) !important;\">\n    <div class=\"card-body p-4\">\n    <h6 class=\"fw-bold text-danger mb-3\"><i class=\"fa-solid fa-triangle-exclamation me-2\"></i> Precautions </h6>\n    <ul class=\"small text-muted mb-0 ps-3 lh-lg\">\n    <li>Once published, the plugin ID should not be changed, as it is part of the directory name and API path</li>\n    <li>Plugin directory overwritten on update. Store persistent data in <code>data</code> dir.</li>\n    <li>Do not modify core files; only use <code>api</code> interfaces.</li>\n    <li>Frontend components must use the ES Module format (<code>export default</code>)</li>\n    <li>Backend entry must export a function (<code>module.exports = async function(api) {}</code>).</li>\n    <li>Socket namespace path: <code>/plugin/[PluginID]/[CustomPath]</code>. Use full path on frontend.</li>\n    <li>Avoid creating long connections or timers in global scope. Do it inside entry and clean up in <code>destroy</code>.</li>\n    <li>Do not communicate directly between plugins. Use global Socket events or shared data directory.</li>\n    </ul>\n    </div>\n    </div>\n    </div>\n    </div>\n    </section>"
            }
        ]
    }
};